1	/**
2	 * Provider that creates the effects bridge, mixer engine, and registry.
3	 * Bridges the effects Zustand store to live Web Audio nodes.
4	 */
5	
6	import { createContext, useContext, useEffect, useRef, useState } from "react";
7	import { useAudioEngine } from "@audio/use-audio-engine";
8	import { createMixerEngine, type MixerEngine } from "@audio/mixer";
9	import type { EffectRegistry } from "./types";
10	import { createDefaultRegistry } from "./default-registry";
11	import { createEffectsBridge, type EffectsBridge } from "./effects-bridge";
12	import { useTransport } from "@audio/use-transport";
13	import { createParamResolver } from "@audio/automation/create-param-resolver";
14	
15	type EffectsBridgeContext = {
16	  readonly registry: EffectRegistry;
17	  readonly mixer: MixerEngine;
18	  readonly bridge: EffectsBridge;
19	};
20	
21	const Ctx = createContext<EffectsBridgeContext | null>(null);
22	
23	export function EffectsBridgeProvider({
24	  children,
25	}: {
26	  children: React.ReactNode;
27	}): React.JSX.Element {
28	  const engine = useAudioEngine();
29	  const transport = useTransport();
30	
31	  const [value] = useState<EffectsBridgeContext>(() => {
32	    const registry = createDefaultRegistry();
33	    const mixer = createMixerEngine(engine.ctx);
34	    const bridge = createEffectsBridge(engine.ctx, registry, mixer);
35	    return { registry, mixer, bridge };
36	  });
37	
38	  // Wire automation param resolver to live mixer AudioParams
39	  useEffect(() => {
40	    transport.setParamResolver(createParamResolver(value.mixer, value.bridge));
41	  }, [value, transport]);
42	
43	  // Guard against StrictMode double-mount: only dispose on true unmount.
44	  // useState initializers are called once and cached in React 18/19,
45	  // so the deferred check is sufficient — no duplicate instances are created.
46	  const mountedRef = useRef(true);
47	  useEffect(() => {
48	    mountedRef.current = true;
49	    return () => {
50	      mountedRef.current = false;
51	      // Defer disposal so StrictMode re-mount can cancel it
52	      setTimeout(() => {
53	        if (!mountedRef.current) {
54	          value.bridge.dispose();
55	          value.mixer.dispose();
56	        }
57	      }, 0);
58	    };
59	  }, [value]);
60	
61	  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
62	}
63	
64	export function useEffectsBridgeContext(): EffectsBridgeContext {
65	  const ctx = useContext(Ctx);
66	  if (ctx === null) {
67	    throw new Error(
68	      "useEffectsBridgeContext must be used within EffectsBridgeProvider",
69	    );
70	  }
71	  return ctx;
72	}
