1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	import { createInsertChain, type InsertChain } from "./insert-chain";
11	import { faderTaper } from "./fader-taper";
12	
13	function clamp(v: number, min: number, max: number): number {
14	  return Math.min(max, Math.max(min, v));
15	}
16	
17	function createMasterBus(ctx: AudioContext): MasterBus {
18	  const inputGain = ctx.createGain();
19	  const faderGain = ctx.createGain();
20	  const limiter = ctx.createDynamicsCompressor();
21	  const analyser = ctx.createAnalyser();
22	
23	  // INV-2: Brickwall limiter settings
24	  limiter.threshold.value = -1;
25	  limiter.ratio.value = 20;
26	  limiter.knee.value = 0;
27	  limiter.attack.value = 0.001;
28	  limiter.release.value = 0.01;
29	
30	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
31	  inputGain.connect(faderGain);
32	  faderGain.connect(limiter);
33	  limiter.connect(analyser);
34	  analyser.connect(ctx.destination);
35	
36	  return { inputGain, faderGain, limiter, analyser };
37	}
38	
39	function createChannelStrip(
40	  ctx: AudioContext,
41	  trackId: string,
42	  masterInput: GainNode,
43	): ChannelStrip {
44	  const inputGain = ctx.createGain();
45	  const preFaderTap = ctx.createGain(); // Unity gain tap for pre-fader sends
46	  const faderGain = ctx.createGain();
47	  const panner = ctx.createStereoPanner();
48	  const muteGain = ctx.createGain();
49	  const analyser = ctx.createAnalyser();
50	
51	  // Chain: inputGain -> [insert chain] -> preFaderTap -> faderGain -> panner -> muteGain -> analyser -> master input
52	  // Note: inputGain -> preFaderTap connection is managed by the insert chain
53	  preFaderTap.connect(faderGain);
54	  faderGain.connect(panner);
55	  panner.connect(muteGain);
56	  muteGain.connect(analyser);
57	  analyser.connect(masterInput);
58	
59	  return {
60	    trackId,
61	    inputGain,
62	    inserts: [],
63	    preFaderTap,
64	    faderGain,
65	    panner,
66	    muteGain,
67	    analyser,
68	    muted: false,
69	    solo: false,
70	    soloIsolate: false,
71	  };
72	}
73	
74	export function createMixerEngine(ctx: AudioContext): MixerEngine {
75	  const master = createMasterBus(ctx);
76	  const strips = new Map<string, ChannelStrip>();
77	  const insertChains = new Map<string, InsertChain>();
78	  let savedMasterLevel = 1;
79	
80	  function applyMuteState(strip: ChannelStrip): void {
81	    const hasSolo = [...strips.values()].some((s) => s.solo);
82	
83	    if (strip.muted) {
84	      strip.muteGain.gain.value = 0;
85	      return;
86	    }
87	
88	    if (hasSolo) {
89	      if (strip.solo || strip.soloIsolate) {
90	        strip.muteGain.gain.value = 1;
91	      } else {
92	        strip.muteGain.gain.value = 0;
93	      }
94	    } else {
95	      strip.muteGain.gain.value = 1;
96	    }
97	  }
98	
99	  const engine: MixerEngine = {
100	    getOrCreateStrip(trackId: string): ChannelStrip {
101	      const existing = strips.get(trackId);
102	      if (existing) return existing;
103	
104	      const strip = createChannelStrip(ctx, trackId, master.inputGain);
105	      strips.set(trackId, strip);
106	      // Insert chain between inputGain and preFaderTap
107	      const chain = createInsertChain(strip.inputGain, strip.preFaderTap);
108	      insertChains.set(trackId, chain);
109	      return strip;
110	    },
111	
112	    removeStrip(trackId: string): void {
113	      const strip = strips.get(trackId);
114	      if (!strip) return;
115	
116	      const chain = insertChains.get(trackId);
117	      chain?.dispose();
118	      insertChains.delete(trackId);
119	
120	      strip.inputGain.disconnect();
121	      strip.preFaderTap.disconnect();
122	      strip.faderGain.disconnect();
123	      strip.panner.disconnect();
124	      strip.muteGain.disconnect();
125	      strip.analyser.disconnect();
126	      strips.delete(trackId);
127	    },
128	
129	    getStrip(trackId: string): ChannelStrip | undefined {
130	      return strips.get(trackId);
131	    },
132	
133	    getAllStrips(): readonly ChannelStrip[] {
134	      return [...strips.values()];
135	    },
136	
137	    getMaster(): MasterBus {
138	      return master;
139	    },
140	
141	    setFaderLevel(trackId: string, level: number): void {
142	      const strip = strips.get(trackId);
143	      if (!strip) return;
144	      if (!Number.isFinite(level)) return;
145	      const clamped = clamp(level, 0, 2);
146	      strip.faderGain.gain.value = faderTaper(clamped);
147	    },
148	
149	    setPan(trackId: string, pan: number): void {
150	      const strip = strips.get(trackId);
151	      if (!strip) return;
152	      strip.panner.pan.value = clamp(pan, -1, 1);
153	    },
154	
155	    setMute(trackId: string, muted: boolean): void {
156	      const strip = strips.get(trackId);
157	      if (!strip) return;
158	      strip.muted = muted;
159	      applyMuteState(strip);
160	    },
161	
162	    setSolo(trackId: string, solo: boolean): void {
163	      const strip = strips.get(trackId);
164	      if (!strip) return;
165	      strip.solo = solo;
166	      engine.updateSoloState();
167	    },
168	
169	    setSoloIsolate(trackId: string, enabled: boolean): void {
170	      const strip = strips.get(trackId);
171	      if (!strip) return;
172	      strip.soloIsolate = enabled;
173	      engine.updateSoloState();
174	    },
175	
176	    updateSoloState(): void {
177	      for (const strip of strips.values()) {
178	        applyMuteState(strip);
179	      }
180	    },
181	
182	    setMasterLevel(level: number): void {
183	      if (!Number.isFinite(level)) return;
184	      savedMasterLevel = clamp(level, 0, 2);
185	      master.faderGain.gain.value = savedMasterLevel;
186	    },
187	
188	    getTrackInput(trackId: string): AudioNode {
189	      return engine.getOrCreateStrip(trackId).inputGain;
190	    },
191	
192	    addInsert(
193	      trackId: string,
194	      id: string,
195	      input: AudioNode,
196	      output: AudioNode,
197	    ): void {
198	      const chain = insertChains.get(trackId);
199	      chain?.addInsert(id, input, output);
200	    },
201	
202	    replaceInsert(
203	      trackId: string,
204	      id: string,
205	      input: AudioNode,
206	      output: AudioNode,
207	    ): void {
208	      const chain = insertChains.get(trackId);
209	      chain?.replaceInsert(id, input, output);
210	    },
211	
212	    removeInsert(trackId: string, insertId: string): void {
213	      const chain = insertChains.get(trackId);
214	      chain?.removeInsert(insertId);
215	    },
216	
217	    emergencyMute(): void {
218	      master.faderGain.gain.value = 0;
219	    },
220	
221	    releaseEmergencyMute(): void {
222	      master.faderGain.gain.value = savedMasterLevel;
223	    },
224	
225	    dispose(): void {
226	      for (const chain of insertChains.values()) {
227	        chain.dispose();
228	      }
229	      insertChains.clear();
230	      for (const strip of strips.values()) {
231	        strip.inputGain.disconnect();
232	        strip.preFaderTap.disconnect();
233	        strip.faderGain.disconnect();
234	        strip.panner.disconnect();
235	        strip.muteGain.disconnect();
236	        strip.analyser.disconnect();
237	      }
238	      strips.clear();
239	      master.inputGain.disconnect();
240	      master.faderGain.disconnect();
241	      master.limiter.disconnect();
242	      master.analyser.disconnect();
243	    },
244	  };
245	
246	  return engine;
247	}
248

1	/**
2	 * Clip playback scheduler.
3	 * Schedules AudioBufferSourceNode instances for clips within the look-ahead window.
4	 * Integrates with the existing LookAheadScheduler pattern.
5	 *
6	 * Time model: clips use arrangement time (seconds on timeline).
7	 * The caller provides a `timeOffset` to convert to AudioContext time:
8	 *   audioContextTime = arrangementTime + timeOffset
9	 */
10	
11	import type { AudioClipModel } from "@state/track/types";
12	
13	type ScheduledClip = {
14	  source: AudioBufferSourceNode;
15	  gainNode: GainNode;
16	  clipId: string;
17	  /** AudioContext time when this clip's playback ends */
18	  endTime: number;
19	};
20	
21	export type ClipScheduler = {
22	  /**
23	   * Schedule clips that overlap the look-ahead window.
24	   * @param clips - Clips to potentially schedule
25	   * @param windowStart - Start of look-ahead window (AudioContext time)
26	   * @param windowEnd - End of look-ahead window (AudioContext time)
27	   * @param timeOffset - Offset to convert arrangement time to AudioContext time
28	   *                     (audioCtxTime = arrangementTime + timeOffset)
29	   * @param getBuffer - Resolve sourceId to AudioBuffer
30	   * @param destination - Node to connect scheduled clips to
31	   */
32	  scheduleClips(
33	    clips: readonly AudioClipModel[],
34	    windowStart: number,
35	    windowEnd: number,
36	    timeOffset: number,
37	    getBuffer: (sourceId: string) => AudioBuffer | undefined,
38	    destination: AudioNode,
39	  ): void;
40	
41	  /** Stop all currently scheduled clips */
42	  stopAll(): void;
43	
44	  /** Clean up completed clips from internal tracking */
45	  cleanup(): void;
46	};
47	
48	export function createClipScheduler(ctx: AudioContext): ClipScheduler {
49	  const scheduled = new Map<string, ScheduledClip>();
50	
51	  return {
52	    scheduleClips(
53	      clips: readonly AudioClipModel[],
54	      windowStart: number,
55	      windowEnd: number,
56	      timeOffset: number,
57	      getBuffer: (sourceId: string) => AudioBuffer | undefined,
58	      destination: AudioNode,
59	    ): void {
60	      for (const clip of clips) {
61	        // Convert arrangement time to AudioContext time
62	        const clipStartCtx = clip.startTime + timeOffset;
63	        const clipEndCtx = clipStartCtx + clip.duration;
64	
65	        // Skip if already scheduled and still playing
66	        if (scheduled.has(clip.id)) continue;
67	
68	        // Check if clip overlaps the look-ahead window
69	        if (clipEndCtx <= windowStart || clipStartCtx >= windowEnd) {
70	          continue;
71	        }
72	
73	        const buffer = getBuffer(clip.sourceId);
74	        if (!buffer) continue;
75	
76	        const source = ctx.createBufferSource();
77	        source.buffer = buffer;
78	
79	        // Compute source offset for mid-clip seeking
80	        const seekOffset =
81	          clipStartCtx < windowStart ? windowStart - clipStartCtx : 0;
82	        const sourceOffset = clip.sourceOffset + seekOffset;
83	        const playDuration = clip.duration - seekOffset;
84	        const playStartCtx = clipStartCtx + seekOffset;
85	
86	        // Create gain node for clip-level gain and fades
87	        const gainNode = ctx.createGain();
88	        gainNode.gain.value = clip.gain;
89	
90	        // Clamp fades to avoid overlap
91	        const maxFadeIn = Math.min(clip.fadeIn, clip.duration);
92	        const maxFadeOut = Math.min(clip.fadeOut, clip.duration - maxFadeIn);
93	
94	        // Apply fade-in (only if we haven't seeked past it)
95	        if (maxFadeIn > 0 && seekOffset < maxFadeIn) {
96	          const fadeInStart = clipStartCtx + seekOffset;
97	          const fadeInRemaining = maxFadeIn - seekOffset;
98	          const startGain =
99	            seekOffset > 0 ? (seekOffset / maxFadeIn) * clip.gain : 0;
100	          gainNode.gain.setValueAtTime(startGain, fadeInStart);
101	          gainNode.gain.linearRampToValueAtTime(
102	            clip.gain,
103	            fadeInStart + fadeInRemaining,
104	          );
105	        }
106	
107	        // Apply fade-out (mirror of fade-in: handle mid-fade seeking)
108	        if (maxFadeOut > 0) {
109	          const fadeOutStartCtx = clipEndCtx - maxFadeOut;
110	          const fadeOutStartInClip = clip.duration - maxFadeOut;
111	
112	          if (seekOffset >= fadeOutStartInClip) {
113	            // Seeking into the fade-out region: compute partial gain
114	            const fadeOutProgress =
115	              (seekOffset - fadeOutStartInClip) / maxFadeOut;
116	            const startGain = clip.gain * (1 - fadeOutProgress);
117	            gainNode.gain.setValueAtTime(startGain, playStartCtx);
118	            gainNode.gain.linearRampToValueAtTime(0, clipEndCtx);
119	          } else {
120	            gainNode.gain.setValueAtTime(clip.gain, fadeOutStartCtx);
121	            gainNode.gain.linearRampToValueAtTime(0, clipEndCtx);
122	          }
123	        }
124	
125	        // Connect: source -> gainNode -> destination
126	        source.connect(gainNode);
127	        gainNode.connect(destination);
128	
129	        // Schedule playback using AudioContext time
130	        source.start(playStartCtx, sourceOffset, playDuration);
131	
132	        const entry: ScheduledClip = {
133	          source,
134	          gainNode,
135	          clipId: clip.id,
136	          endTime: clipEndCtx,
137	        };
138	        scheduled.set(clip.id, entry);
139	
140	        // Auto-cleanup when playback ends
141	        source.addEventListener("ended", () => {
142	          // Only remove if this is still the active entry for this clip
143	          const current = scheduled.get(clip.id);
144	          if (current === entry) {
145	            gainNode.disconnect();
146	            scheduled.delete(clip.id);
147	          }
148	        });
149	      }
150	    },
151	
152	    stopAll(): void {
153	      for (const entry of scheduled.values()) {
154	        try {
155	          entry.source.stop();
156	        } catch {
157	          // Source may have already stopped
158	        }
159	        entry.gainNode.disconnect();
160	      }
161	      scheduled.clear();
162	    },
163	
164	    cleanup(): void {
165	      const now = ctx.currentTime;
166	      for (const [id, entry] of scheduled) {
167	        if (entry.endTime <= now) {
168	          entry.gainNode.disconnect();
169	          scheduled.delete(id);
170	        }
171	      }
172	    },
173	  };
174	}
