1	/**
2	 * Controller hook that bridges the transport audio layer to the Zustand store.
3	 * Creates and manages TransportClock, LookAheadScheduler, Metronome,
4	 * and AutomationScheduler.
5	 *
6	 * useTransportInit() — initialization (used only by TransportProvider)
7	 * useTransport()     — context consumer (used by all other components)
8	 */
9	
10	import { useCallback, useContext, useEffect, useRef } from "react";
11	import { useAudioEngine } from "./use-audio-engine";
12	import { createTransportClock, type TransportClock } from "./transport-clock";
13	import {
14	  createLookAheadScheduler,
15	  type LookAheadScheduler,
16	} from "./look-ahead-scheduler";
17	import { createMetronome, type Metronome } from "./metronome";
18	import {
19	  createAutomationScheduler,
20	  type AutomationScheduler,
21	  type ParamResolver,
22	} from "./automation/automation-scheduler";
23	import {
24	  createSharedBuffers,
25	  type SharedArrayBufferLayout,
26	} from "./shared-buffer-layout";
27	import { useDawStore } from "@state/index";
28	import { useAutomationStore } from "@state/automation";
29	import { TransportCtx } from "./transport-ctx";
30	
31	export type UseTransportReturn = {
32	  play(): void;
33	  pause(): void;
34	  stop(): void;
35	  seek(seconds: number): void;
36	  setBpm(bpm: number): void;
37	  setMetronomeEnabled(on: boolean): void;
38	  getTransportSAB(): SharedArrayBuffer | null;
39	  getClock(): TransportClock | null;
40	  /** Set the param resolver for automation playback (call from mixer provider) */
41	  setParamResolver(resolver: ParamResolver): void;
42	};
43	
44	/**
45	 * Initializes the transport audio stack. Used only by TransportProvider.
46	 */
47	export function useTransportInit(): UseTransportReturn {
48	  const engine = useAudioEngine();
49	  const clockRef = useRef<TransportClock | null>(null);
50	  const schedulerRef = useRef<LookAheadScheduler | null>(null);
51	  const metronomeRef = useRef<Metronome | null>(null);
52	  const autoSchedulerRef = useRef<AutomationScheduler | null>(null);
53	  const paramResolverRef = useRef<ParamResolver>(() => undefined);
54	  const sabRef = useRef<SharedArrayBufferLayout | null>(null);
55	
56	  const storePlay = useDawStore((s) => s.play);
57	  const storePause = useDawStore((s) => s.pause);
58	  const storeStop = useDawStore((s) => s.stop);
59	  const storeSetBpm = useDawStore((s) => s.setBpm);
60	  const storeSetCursor = useDawStore((s) => s.setCursor);
61	  const bpm = useDawStore((s) => s.bpm);
62	  const loopEnabled = useDawStore((s) => s.loopEnabled);
63	  const loopStart = useDawStore((s) => s.loopStart);
64	  const loopEnd = useDawStore((s) => s.loopEnd);
65	
66	  // Sync loop region from store to clock
67	  useEffect(() => {
68	    clockRef.current?.setLoop({
69	      enabled: loopEnabled,
70	      start: loopStart,
71	      end: loopEnd,
72	    });
73	  }, [loopEnabled, loopStart, loopEnd]);
74	
75	  // Initialize on mount
76	  useEffect(() => {
77	    const sab = createSharedBuffers();
78	    sabRef.current = sab;
79	
80	    const clock = createTransportClock(engine.ctx, sab.transport, bpm);
81	    clockRef.current = clock;
82	
83	    const met = createMetronome(engine.ctx);
84	    metronomeRef.current = met;
85	
86	    // Automation scheduler: resolver is ref-based so it can be set later by mixer
87	    const autoSched = createAutomationScheduler((lane) =>
88	      paramResolverRef.current(lane),
89	    );
90	    autoSchedulerRef.current = autoSched;
91	
92	    const scheduler = createLookAheadScheduler(
93	      engine.ctx,
94	      clock,
95	      undefined,
96	      (beatTime: number, beatNumber: number) => {
97	        const beatsPerBar = clock.getTempoMap().timeSignature.numerator;
98	        const isDownbeat = beatNumber % beatsPerBar === 0;
99	        met.scheduleTick(beatTime, isDownbeat);
100	      },
101	      (windowStart: number, windowEnd: number, timeOffset: number) => {
102	        // Gather all armed lanes from the automation store
103	        const allLanes = useAutomationStore.getState().lanes;
104	        const lanes = Object.values(allLanes).flat();
105	        autoSched.scheduleWindow(lanes, windowStart, windowEnd, timeOffset);
106	      },
107	    );
108	    schedulerRef.current = scheduler;
109	
110	    return () => {
111	      scheduler.stop();
112	      autoSched.cancelAll();
113	      met.dispose();
114	      clock.dispose();
115	      clockRef.current = null;
116	      schedulerRef.current = null;
117	      metronomeRef.current = null;
118	      autoSchedulerRef.current = null;
119	      sabRef.current = null;
120	    };
121	    // eslint-disable-next-line react-hooks/exhaustive-deps -- init once
122	  }, [engine]);
123	
124	  const play = useCallback((): void => {
125	    const clock = clockRef.current;
126	    const scheduler = schedulerRef.current;
127	    if (clock === null || scheduler === null) return;
128	    if (clock.state === "playing") return;
129	
130	    clock.play();
131	    scheduler.start();
132	    storePlay();
133	  }, [storePlay]);
134	
135	  const pause = useCallback((): void => {
136	    const clock = clockRef.current;
137	    const scheduler = schedulerRef.current;
138	    if (clock === null || scheduler === null) return;
139	    if (clock.state !== "playing") return;
140	
141	    clock.pause();
142	    scheduler.stop();
143	    autoSchedulerRef.current?.cancelAll();
144	    storeSetCursor(clock.getCursorSeconds());
145	    storePause();
146	  }, [storePause, storeSetCursor]);
147	
148	  const stop = useCallback((): void => {
149	    const clock = clockRef.current;
150	    const scheduler = schedulerRef.current;
151	    const met = metronomeRef.current;
152	    if (clock === null || scheduler === null) return;
153	
154	    // INV-6: Guarantee silence within 10ms
155	    met?.silence();
156	    clock.stop();
157	    scheduler.stop();
158	    autoSchedulerRef.current?.cancelAll();
159	    storeSetCursor(0);
160	    storeStop();
161	  }, [storeStop, storeSetCursor]);
162	
163	  const seek = useCallback(
164	    (seconds: number): void => {
165	      const clock = clockRef.current;
166	      if (clock === null) return;
167	
168	      clock.seek(seconds);
169	      schedulerRef.current?.sync();
170	      storeSetCursor(clock.getCursorSeconds());
171	    },
172	    [storeSetCursor],
173	  );
174	
175	  const setBpm = useCallback(
176	    (newBpm: number): void => {
177	      const clock = clockRef.current;
178	      if (clock === null) return;
179	
180	      clock.setBpm(newBpm);
181	      storeSetBpm(newBpm);
182	    },
183	    [storeSetBpm],
184	  );
185	
186	  const setMetronomeEnabled = useCallback((on: boolean): void => {
187	    metronomeRef.current?.setEnabled(on);
188	  }, []);
189	
190	  const getTransportSAB = useCallback((): SharedArrayBuffer | null => {
191	    return sabRef.current?.transport ?? null;
192	  }, []);
193	
194	  const getClock = useCallback((): TransportClock | null => {
195	    return clockRef.current;
196	  }, []);
197	
198	  const setParamResolver = useCallback((resolver: ParamResolver): void => {
199	    paramResolverRef.current = resolver;
200	  }, []);
201	
202	  return {
203	    play,
204	    pause,
205	    stop,
206	    seek,
207	    setBpm,
208	    setMetronomeEnabled,
209	    getTransportSAB,
210	    getClock,
211	    setParamResolver,
212	  };
213	}
214	
215	/**
216	 * Context consumer hook. Must be used within a TransportProvider.
217	 */
218	export function useTransport(): UseTransportReturn {
219	  const transport = useContext(TransportCtx);
220	  if (transport === null) {
221	    throw new Error("useTransport must be used within TransportProvider");
222	  }
223	  return transport;
224	}
