1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import { Toolbar } from "./Toolbar";
3	import { ArrangementPanel } from "@ui/arrangement";
4	import { InstrumentPanel } from "./panels";
5	import { MixerPanel } from "./mixer";
6	import { MediaPoolPanel } from "./media-pool/MediaPoolPanel";
7	import { PianoRollEditor } from "@ui/piano-roll/PianoRollEditor";
8	import { CommandRegistry } from "./keyboard/command-registry";
9	import { ShortcutMap } from "./keyboard/shortcut-map";
10	import { useKeyboardShortcuts } from "./keyboard/useKeyboardShortcuts";
11	import { useTransportShortcuts } from "./transport/useTransportShortcuts";
12	import { useSessionShortcuts } from "./session/useSessionShortcuts";
13	import { RecoveryDialog } from "./session/RecoveryDialog";
14	import { TransportProvider } from "@audio/transport-provider";
15	import { EffectsBridgeProvider } from "@audio/effects/EffectsBridgeProvider";
16	import { RoutingBridgeProvider } from "@audio/mixer/RoutingBridgeProvider";
17	import { useMediaPool } from "@audio/media-pool/use-media-pool";
18	import { useDawStore } from "@state/store";
19	import { sharedUndoManager } from "@state/undo/shared-undo-manager";
20	import { useSessionPersistence } from "@state/session/use-session-persistence";
21	import type { SessionStorage } from "@state/session/session-storage";
22	import { createDefaultSession } from "@state/session/session-schema";
23	import { hydrateStore } from "@state/session/use-session-persistence";
24	import { ErrorBoundary } from "./ErrorBoundary";
25	import { KeyboardShortcutsPanel } from "./keyboard/KeyboardShortcutsPanel";
26	import { ActionToast } from "./primitives/ActionToast";
27	
28	export type BottomPanelMode = "default" | "piano-roll";
29	
30	function DawShellInner({
31	  sessionStorage,
32	  idbWarning,
33	}: {
34	  sessionStorage: SessionStorage;
35	  idbWarning: boolean;
36	}): React.JSX.Element {
37	  const registry = useMemo(() => new CommandRegistry(), []);
38	  const shortcuts = useMemo(() => new ShortcutMap(), []);
39	  const pool = useMediaPool();
40	  const undoManager = sharedUndoManager;
41	  const { saveNow, recoveryWarnings } = useSessionPersistence(sessionStorage);
42	  const [dismissed, setDismissed] = useState(false);
43	  const [shortcutsOpen, setShortcutsOpen] = useState(false);
44	  const [toastMessage, setToastMessage] = useState<string | null>(null);
45	  const [bottomPanel, setBottomPanel] = useState<BottomPanelMode>("default");
46	  const [editingClipId, setEditingClipId] = useState<string | null>(null);
47	
48	  const openPianoRoll = useCallback((clipId: string) => {
49	    setEditingClipId(clipId);
50	    setBottomPanel("piano-roll");
51	  }, []);
52	
53	  const closePianoRoll = useCallback(() => {
54	    setEditingClipId(null);
55	    setBottomPanel("default");
56	  }, []);
57	
58	  // If the editing clip was deleted (e.g. via undo), fall back to default panel
59	  const clipStillExists = useDawStore(
60	    (s) => editingClipId !== null && s.clips[editingClipId] !== undefined,
61	  );
62	  const effectivePanel: BottomPanelMode =
63	    bottomPanel === "piano-roll" && !clipStillExists ? "default" : bottomPanel;
64	
65	  const toastCountRef = useRef(0);
66	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
67	
68	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
69	
70	  const showToast = useCallback((msg: string) => {
71	    toastCountRef.current += 1;
72	    setToastMessage(`${msg}#${String(toastCountRef.current)}`);
73	  }, []);
74	
75	  useEffect(() => {
76	    if (idbWarning) {
77	      showToast("Storage unavailable -- changes won't persist");
78	    }
79	  }, [idbWarning, showToast]);
80	
81	  useTransportShortcuts(registry, shortcuts);
82	  useSessionShortcuts(
83	    registry,
84	    shortcuts,
85	    undoManager,
86	    stableSaveNow,
87	    showToast,
88	  );
89	
90	  useEffect(() => {
91	    registry.register({
92	      id: "app.shortcuts-legend",
93	      label: "Toggle Keyboard Shortcuts",
94	      execute: () => {
95	        setShortcutsOpen((prev) => !prev);
96	      },
97	    });
98	    shortcuts.bind({
99	      key: "?",
100	      shift: true,
101	      commandId: "app.shortcuts-legend",
102	    });
103	    return () => {
104	      registry.unregister("app.shortcuts-legend");
105	      shortcuts.unbind("app.shortcuts-legend");
106	    };
107	  }, [registry, shortcuts]);
108	
109	  useKeyboardShortcuts(registry, shortcuts);
110	
111	  return (
112	    <div
113	      data-testid="daw-shell"
114	      style={{
115	        display: "flex",
116	        flexDirection: "column",
117	        height: "100vh",
118	        backgroundColor: "var(--color-black)",
119	      }}
120	    >
121	      <Toolbar />
122	      <ErrorBoundary fallbackLabel="Panel crashed">
123	        <div
124	          style={{
125	            display: "flex",
126	            flexDirection: "column",
127	            flex: 1,
128	            overflow: "hidden",
129	          }}
130	        >
131	          <ArrangementPanel onOpenPianoRoll={openPianoRoll} />
132	          <MixerPanel />
133	          {effectivePanel === "piano-roll" ? (
134	            <div
135	              style={{ position: "relative", overflow: "hidden", height: 240 }}
136	            >
137	              <button
138	                type="button"
139	                data-testid="close-piano-roll"
140	                onClick={closePianoRoll}
141	                style={{
142	                  position: "absolute",
143	                  top: 4,
144	                  right: 8,
145	                  zIndex: 10,
146	                  background: "none",
147	                  border: "var(--border)",
148	                  color: "var(--color-gray-300)",
149	                  cursor: "pointer",
150	                  fontFamily: "var(--font-mono)",
151	                  fontSize: "var(--text-xs)",
152	                  padding: "2px 8px",
153	                }}
154	              >
155	                Close
156	              </button>
157	              <PianoRollEditor clipId={editingClipId} />
158	            </div>
159	          ) : (
160	            <div style={{ display: "flex", overflow: "hidden" }}>
161	              <div style={{ flex: 1 }}>
162	                <InstrumentPanel />
163	              </div>
164	              <div style={{ flex: 1 }}>
165	                <MediaPoolPanel pool={pool} />
166	              </div>
167	            </div>
168	          )}
169	        </div>
170	      </ErrorBoundary>
171	      <KeyboardShortcutsPanel
172	        open={shortcutsOpen}
173	        onClose={() => {
174	          setShortcutsOpen(false);
175	        }}
176	      />
177	      <RecoveryDialog
178	        open={showRecovery}
179	        warnings={recoveryWarnings}
180	        onAccept={() => {
181	          setDismissed(true);
182	        }}
183	        onDiscard={() => {
184	          hydrateStore(createDefaultSession());
185	          setDismissed(true);
186	        }}
187	      />
188	      <ActionToast message={toastMessage} />
189	    </div>
190	  );
191	}
192	
193	export function DawShell({
194	  sessionStorage,
195	  idbWarning = false,
196	}: {
197	  sessionStorage: SessionStorage;
198	  idbWarning?: boolean;
199	}): React.JSX.Element {
200	  return (
201	    <TransportProvider>
202	      <EffectsBridgeProvider>
203	        <RoutingBridgeProvider>
204	          <DawShellInner
205	            sessionStorage={sessionStorage}
206	            idbWarning={idbWarning}
207	          />
208	        </RoutingBridgeProvider>
209	      </EffectsBridgeProvider>
210	    </TransportProvider>
211	  );
212	}
