93	    setPattern(seq.getPattern());
94	  }, [seq]);
95	
96	  // Transport sync: advance step indicator when playing
97	  const rafRef = useRef(0);
98	  useEffect(() => {
99	    if (transportState !== "playing") return;
100	
101	    const clock = transport.getClock();
102	    if (!clock) return;
103	
104	    const stepsPerBeat = 4; // 16th notes
105	    let lastStep = -1;
106	
107	    const tick = (): void => {
108	      const cursor = clock.getCursorSeconds();
109	      const stepDuration = 60 / (bpm * stepsPerBeat);
110	      const step = Math.floor(cursor / stepDuration) % pattern.steps.length;
111	      if (step !== lastStep) {
112	        lastStep = step;
113	        setLiveStep(step);
114	      }
115	      rafRef.current = requestAnimationFrame(tick);
116	    };
117	    rafRef.current = requestAnimationFrame(tick);
118	
119	    return () => {
120	      cancelAnimationFrame(rafRef.current);
121	    };
122	  }, [transportState, transport, bpm, pattern.steps.length]);
123	
124	  // Derive currentStep: 0 when stopped, liveStep when playing/paused
125	  const currentStep = transportState === "stopped" ? 0 : liveStep;
126	
127	  const onToggleStep = useCallback(
128	    (instrumentId: DrumInstrumentId, stepIndex: number) => {
129	      seq.toggleStep(instrumentId, stepIndex);
130	      setPattern(seq.getPattern());
131	    },
132	    [seq],
133	  );
134	
135	  const onSetAccent = useCallback(
136	    (stepIndex: number, accent: boolean) => {
137	      seq.setAccent(stepIndex, accent);
138	      setPattern(seq.getPattern());
139	    },
140	    [seq],
141	  );
142	
143	  // TODO: wire to audio engine for pad preview
144	  const onTriggerPad = useCallback((_instrumentId: DrumInstrumentId) => {}, []);
145	
146	  // TODO: propagate param changes to audio engine
147	  const onParamChange = useCallback(
148	    (
149	      instrumentId: DrumInstrumentId,
150	      key: keyof DrumInstrumentParams,
151	      value: number,
152	    ) => {
153	      setParams((prev) => {
154	        const next = {
155	          ...prev,
156	          [instrumentId]: { ...prev[instrumentId], [key]: value },
157	        };
158	        paramsCache.set(trackId, next);
159	        return next;
160	      });
161	    },
162	    [trackId],
163	  );
164	
165	  const onSwitchPattern = useCallback(
166	    (name: string) => {
167	      seq.switchPattern(name);
168	      setPattern(seq.getPattern());
169	    },
170	    [seq],
171	  );
172	
173	  const onClearPattern = useCallback(() => {
174	    seq.clearPattern();
175	    setPattern(seq.getPattern());
176	  }, [seq]);
177	
178	  return {
179	    pattern,
180	    currentStep,
181	    params,
182	    onToggleStep,
183	    onSetAccent,
184	    onTriggerPad,
185	    onParamChange,
186	    onSwitchPattern,
187	    onClearPattern,
188	  };
189	}
