107	export const useDawStore = create<DawStore>()((set, get) => ({
108	  // Transport defaults
109	  transportState: "stopped",
110	  bpm: 120,
111	  cursorSeconds: 0,
112	  loopEnabled: false,
113	  loopStart: 0,
114	  loopEnd: 0,
115	
116	  // Engine defaults
117	  engineStatus: "uninitialized",
118	
119	  // Mixer defaults
120	  masterVolume: 1,
121	
122	  // Track & clip defaults
123	  tracks: [],
124	  clips: {},
125	  selectedTrackIds: [],
126	  selectedClipIds: [],
127	  selectedNoteIds: [],
128	
129	  // Transport actions
130	  play: () => {
131	    set({ transportState: "playing" });
132	  },
133	  pause: () => {
134	    set({ transportState: "paused" });
135	  },
136	  stop: () => {
137	    set({ transportState: "stopped", cursorSeconds: 0 });
138	  },
139	  setBpm: (bpm: number) => {
140	    const clamped = Math.min(999, Math.max(20, bpm));
141	    if (!Number.isFinite(clamped)) return;
142	    set({ bpm: clamped });
143	  },
144	  setCursor: (seconds: number) => {
145	    set({ cursorSeconds: seconds });
146	  },
147	  setLoop: (enabled: boolean, start?: number, end?: number) => {
148	    set((state) => ({
149	      loopEnabled: enabled,
150	      loopStart: start ?? state.loopStart,
151	      loopEnd: end ?? state.loopEnd,
152	    }));
153	  },
154	
155	  // Engine actions
156	  setEngineStatus: (status: AudioEngineStatus) => {
157	    set({ engineStatus: status });
158	  },
159	
160	  // Mixer actions
161	  setMasterVolume: (volume: number) => {
162	    const clamped = Math.min(2, Math.max(0, volume));
163	    set({ masterVolume: clamped });
