417	      const updated: MidiClipModel = {
418	        ...clip,
419	        noteEvents: clip.noteEvents.filter((n) => n.id !== noteId),
420	      };
421	      return { clips: { ...state.clips, [clipId]: updated } };
422	    });
423	  },
