442	        ),
443	      };
444	      return { clips: { ...state.clips, [clipId]: updated } };
445	    });
446	  },
447	
448	  resizeNoteEvent: (clipId: string, noteId: string, newDuration: number) => {
449	    set((state) => {
450	      const clip = state.clips[clipId];
451	      if (!clip || !isMidiClip(clip)) return state;
452	      const clampedDuration = Math.max(0.01, newDuration);
453	      const updated: MidiClipModel = {
454	        ...clip,
455	        noteEvents: clip.noteEvents.map((n) =>
456	          n.id === noteId ? { ...n, duration: clampedDuration } : n,
457	        ),
458	      };
459	      return { clips: { ...state.clips, [clipId]: updated } };
460	    });
461	  },
462	
463	  updateNoteVelocity: (clipId: string, noteId: string, velocity: number) => {
464	    set((state) => {
465	      const clip = state.clips[clipId];
466	      if (!clip || !isMidiClip(clip)) return state;
467	      const clampedVelocity = Math.max(0, Math.min(127, Math.round(velocity)));
468	      const updated: MidiClipModel = {
469	        ...clip,
470	        noteEvents: clip.noteEvents.map((n) =>
471	          n.id === noteId ? { ...n, velocity: clampedVelocity } : n,
472	        ),
473	      };
474	      return { clips: { ...state.clips, [clipId]: updated } };
475	    });
476	  },
477	
478	  // Selection
479	  setSelectedTrackIds: (ids: readonly string[]) => {
480	    set({ selectedTrackIds: ids });
481	  },
482	  setSelectedClipIds: (ids: readonly string[]) => {
483	    set({ selectedClipIds: ids });
484	  },
485	  setSelectedNoteIds: (ids: readonly string[]) => {
486	    set({ selectedNoteIds: ids });
487	  },
488	
489	  // Query
490	  queryClipsAtTime: (time: number): readonly ClipModel[] => {
491	    const state = get();
492	    const hasSolo = state.tracks.some((t) => t.solo);
493	    const activeTracks = new Set(
494	      state.tracks
495	        .filter((t) => {
496	          if (t.muted) return false;
497	          if (hasSolo && !t.solo && !t.soloIsolate) return false;
498	          return true;
499	        })
500	        .map((t) => t.id),
501	    );
502	
503	    return Object.values(state.clips).filter((clip) => {
504	      if (!activeTracks.has(clip.trackId)) return false;
505	      const clipEnd = clip.startTime + clip.duration;
506	      return time >= clip.startTime && time < clipEnd;
507	    });
508	  },
509	}));
