1	/**
2	 * Bridge between the modulation Zustand store and the synth AudioWorklet.
3	 * Subscribes to store changes and forwards WorkletModRoute[] to the instrument.
4	 *
5	 * Usage: call `subscribeModRoutes(trackId, instrument)` when an instrument
6	 * is created for a track. Returns an unsubscribe function for cleanup.
7	 */
8	
9	import { useModulationStore } from "@state/synth/modulation-store";
10	import type { SynthInstrument } from "./synth-instrument";
11	
12	/**
13	 * Subscribe a SynthInstrument to modulation store changes for the given track.
14	 * Immediately sends current routes, then forwards any future changes.
15	 * Returns an unsubscribe function.
16	 */
17	export function subscribeModRoutes(
18	  trackId: string,
19	  instrument: SynthInstrument,
20	): () => void {
21	  // Send current routes immediately
22	  const currentRoutes = useModulationStore.getState().getWorkletRoutes(trackId);
23	  instrument.setModRoutes(currentRoutes);
24	
25	  // Subscribe to future changes
26	  let prevJson = JSON.stringify(currentRoutes);
27	
28	  return useModulationStore.subscribe((state) => {
29	    const routes = state.getWorkletRoutes(trackId);
30	    const json = JSON.stringify(routes);
31	    // Only send when routes actually changed (avoid redundant messages)
32	    if (json !== prevJson) {
33	      prevJson = json;
34	      instrument.setModRoutes(routes);
35	    }
36	  });
37	}
