1	/**
2	 * Bridge between routing Zustand store and the RoutingEngine.
3	 * Subscribes to store changes, creates/disposes buses, sends, sidechains,
4	 * and wires pre/post-fader sends to the correct channel strip tap point.
5	 */
6	
7	import type { RoutingEngine, SendRoute } from "./routing";
8	import type { MixerEngine } from "./types";
9	import { useRoutingStore } from "@state/routing/routing-store";
10	
11	export type RoutingBridge = {
12	  dispose(): void;
13	};
14	
15	export function createRoutingBridge(
16	  routing: RoutingEngine,
17	  mixer: MixerEngine,
18	): RoutingBridge {
19	  // Track which sends are wired so we can re-wire on preFader toggle
20	  const wiredSends = new Map<string, { send: SendRoute; preFader: boolean }>();
21	  const knownBuses = new Set<string>();
22	  const knownSidechains = new Set<string>();
23	
24	  function sendKey(trackId: string, busId: string): string {
25	    return `${trackId}:${busId}`;
26	  }
27	
28	  function scKey(sourceId: string, targetId: string): string {
29	    return `${sourceId}:${targetId}`;
30	  }
31	
32	  function wireSend(trackId: string, send: SendRoute, preFader: boolean): void {
33	    const strip = mixer.getStrip(trackId) ?? mixer.getOrCreateStrip(trackId);
34	    const tap = preFader ? strip.preFaderTap : strip.faderGain;
35	    tap.connect(send.sendGain);
36	    wiredSends.set(sendKey(trackId, send.busId), { send, preFader });
37	  }
38	
39	  function unwireSend(trackId: string, busId: string): void {
40	    const key = sendKey(trackId, busId);
41	    const wired = wiredSends.get(key);
42	    if (!wired) return;
43	
44	    const strip = mixer.getStrip(trackId);
45	    if (strip) {
46	      const tap = wired.preFader ? strip.preFaderTap : strip.faderGain;
47	      try {
48	        tap.disconnect(wired.send.sendGain);
49	      } catch {
50	        // Already disconnected
51	      }
52	    }
53	    wiredSends.delete(key);
54	  }
55	
56	  function sync(): void {
57	    const state = useRoutingStore.getState();
58	
59	    // Sync buses: add new, remove stale
60	    const storeBusIds = new Set(Object.keys(state.buses));
61	    for (const id of knownBuses) {
62	      if (!storeBusIds.has(id)) {
63	        routing.removeBus(id);
64	        knownBuses.delete(id);
65	      }
66	    }
67	    for (const [id, bus] of Object.entries(state.buses)) {
68	      if (!knownBuses.has(id)) {
69	        routing.createBus(id);
70	        knownBuses.add(id);
71	      }
72	      // Sync output target
73	      const engineBus = routing.getBus(id);
74	      if (engineBus && engineBus.outputTarget !== bus.outputTarget) {
75	        try {
76	          routing.setBusOutput(id, bus.outputTarget);
77	        } catch {
78	          // Cycle or invalid target -- store is out of sync, skip
79	        }
80	      }
81	    }
82	
83	    // Sync sends
84	    const activeSendKeys = new Set<string>();
85	    for (const [trackId, trackSends] of Object.entries(state.sends)) {
86	      for (const sendState of trackSends) {
87	        const key = sendKey(trackId, sendState.busId);
88	        activeSendKeys.add(key);
89	
90	        const wired = wiredSends.get(key);
91	        if (wired) {
92	          // Update level
93	          if (wired.send.level !== sendState.level) {
94	            routing.setSendLevel(trackId, sendState.busId, sendState.level);
95	          }
96	          // Re-wire if preFader changed
97	          if (wired.preFader !== sendState.preFader) {
98	            unwireSend(trackId, sendState.busId);
99	            wireSend(trackId, wired.send, sendState.preFader);
100	          }
101	        } else {
102	          // New send
103	          try {
104	            const send = routing.addSend(trackId, sendState.busId, {
105	              level: sendState.level,
106	              preFader: sendState.preFader,
107	            });
108	            wireSend(trackId, send, sendState.preFader);
109	          } catch {
110	            // Bus not found or cycle -- skip
111	          }
112	        }
113	      }
114	    }
115	
116	    // Remove stale sends
117	    for (const key of [...wiredSends.keys()]) {
118	      if (!activeSendKeys.has(key)) {
119	        const [trackId, busId] = key.split(":");
120	        if (trackId !== undefined && busId !== undefined) {
121	          unwireSend(trackId, busId);
122	          routing.removeSend(trackId, busId);
123	        }
124	      }
125	    }
126	
127	    // Sync sidechains
128	    const activeScKeys = new Set<string>();
129	    for (const sc of state.sidechains) {
130	      const key = scKey(sc.sourceId, sc.targetId);
131	      activeScKeys.add(key);
132	      if (!knownSidechains.has(key)) {
133	        routing.addSidechain(sc.sourceId, sc.targetId);
134	        knownSidechains.add(key);
135	      }
136	    }
137	    for (const key of [...knownSidechains]) {
138	      if (!activeScKeys.has(key)) {
139	        const [sourceId, targetId] = key.split(":");
140	        if (sourceId !== undefined && targetId !== undefined) {
141	          routing.removeSidechain(sourceId, targetId);
142	        }
143	        knownSidechains.delete(key);
144	      }
145	    }
146	  }
147	
148	  // Initial sync
149	  sync();
150	
151	  // Subscribe to store changes
152	  const unsub = useRoutingStore.subscribe(sync);
153	
154	  return {
155	    dispose(): void {
156	      unsub();
157	      for (const key of [...wiredSends.keys()]) {
158	        const [trackId, busId] = key.split(":");
159	        if (trackId !== undefined && busId !== undefined) {
160	          unwireSend(trackId, busId);
161	        }
162	      }
163	    },
164	  };
165	}
