1	/**
2	 * Look-ahead scheduler using the Chris Wilson pattern:
3	 * setInterval fires every ~25ms, scheduling audio events
4	 * that fall within the next 100ms of AudioContext time.
5	 *
6	 * This runs on the main thread. The setInterval callback is lightweight
7	 * (just math + scheduling calls), so it doesn't block rendering.
8	 */
9	
10	import type { TransportClock } from "./transport-clock";
11	
12	export type SchedulerConfig = {
13	  intervalMs: number;
14	  lookAheadMs: number;
15	};
16	
17	export type LookAheadScheduler = {
18	  start(): void;
19	  stop(): void;
20	  /** Re-sync beat phase to the current clock position (e.g. after seek). */
21	  sync(): void;
22	  readonly isRunning: boolean;
23	};
24	
25	const DEFAULT_CONFIG: SchedulerConfig = {
26	  intervalMs: 25,
27	  lookAheadMs: 100,
28	};
29	
30	export function createLookAheadScheduler(
31	  ctx: AudioContext,
32	  clock: TransportClock,
33	  config?: Partial<SchedulerConfig>,
34	  onTick?: (beatTime: number, beatNumber: number) => void,
35	  onAdvance?: (
36	    windowStart: number,
37	    windowEnd: number,
38	    timeOffset: number,
39	  ) => void,
40	): LookAheadScheduler {
41	  const intervalMs = config?.intervalMs ?? DEFAULT_CONFIG.intervalMs;
42	  const lookAheadSec =
43	    (config?.lookAheadMs ?? DEFAULT_CONFIG.lookAheadMs) / 1000;
44	
45	  let timerId: ReturnType<typeof setInterval> | null = null;
46	  let nextBeatTime = 0;
47	  let currentBeat = 0;
48	
49	  function syncToPosition(cursorSec: number): void {
50	    const spb = clock.getTempoMap().secondsPerBeat();
51	    const totalBeats = cursorSec / spb;
52	    const wholeBeat = Math.floor(totalBeats + 1e-9);
53	    const remainder = totalBeats - wholeBeat;
54	
55	    if (remainder < 1e-6) {
56	      // On a beat boundary — schedule this beat now
57	      currentBeat = wholeBeat;
58	      nextBeatTime = ctx.currentTime;
59	    } else {
60	      // Between beats — schedule next beat
61	      currentBeat = wholeBeat + 1;
62	      nextBeatTime = ctx.currentTime + (currentBeat * spb - cursorSec);
63	    }
64	  }
65	
66	  function advance(): void {
67	    if (clock.state !== "playing") return;
68	
69	    // Drive SAB cursor updates and detect loop wraps
70	    clock.updateCursor();
71	
72	    if (clock.didLoopWrap()) {
73	      syncToPosition(clock.getCursorSeconds());
74	    }
75	
76	    const scheduleUntil = ctx.currentTime + lookAheadSec;
77	    const spb = clock.getTempoMap().secondsPerBeat();
78	
79	    // Constrain scheduling window to the loop end boundary
80	    const loop = clock.getLoop();
81	    let effectiveUntil = scheduleUntil;
82	    if (loop.enabled && loop.end > loop.start) {
83	      const cursorNow = clock.getCursorSeconds();
84	      const timeToLoopEnd = loop.end - cursorNow;
85	      if (timeToLoopEnd > 0) {
86	        effectiveUntil = Math.min(
87	          scheduleUntil,
88	          ctx.currentTime + timeToLoopEnd,
89	        );
90	      }
91	    }
92	
93	    // Fire window-level callback for continuous schedulers (automation, clips)
94	    const timeOffset = ctx.currentTime - clock.getCursorSeconds();
95	    try {
96	      onAdvance?.(ctx.currentTime, effectiveUntil, timeOffset);
97	    } catch (e) {
98	      console.error("[Scheduler] onAdvance callback error:", e);
99	    }
100	
101	    while (nextBeatTime < effectiveUntil) {
102	      try {
103	        onTick?.(nextBeatTime, currentBeat);
104	      } catch (e) {
105	        console.error("[Scheduler] onTick callback error:", e);
106	      }
107	      currentBeat++;
108	      nextBeatTime += spb;
109	    }
110	  }
111	
112	  const scheduler: LookAheadScheduler = {
113	    get isRunning(): boolean {
114	      return timerId !== null;
115	    },
116	
117	    start(): void {
118	      if (timerId !== null) return;
119	
120	      // Phase-correct: sync beat position to current cursor
121	      syncToPosition(clock.getCursorSeconds());
122	
123	      timerId = setInterval(advance, intervalMs);
124	      advance();
125	    },
126	
127	    stop(): void {
128	      if (timerId !== null) {
129	        clearInterval(timerId);
130	        timerId = null;
131	      }
132	      nextBeatTime = 0;
133	      currentBeat = 0;
134	    },
135	
136	    sync(): void {
137	      syncToPosition(clock.getCursorSeconds());
138	    },
139	  };
140	
141	  return scheduler;
142	}
143

1	/**
2	 * Automation scheduler for sample-accurate AudioParam playback.
3	 * Evaluates automation curves at exact breakpoints within scheduling windows
4	 * and applies values to AudioParams via setValueAtTime / linearRampToValueAtTime.
5	 *
6	 * Designed to be called from the look-ahead scheduler's advance callback.
7	 */
8	
9	import type { AutomationLane, ParameterRange } from "./automation-types";
10	import {
11	  evaluateCurve,
12	  denormalize,
13	  findPointsInRange,
14	} from "./automation-curve";
15	
16	/** Resolved parameter binding: the AudioParam to automate and its value range */
17	export type ResolvedParam = {
18	  /** The AudioParam or AudioParam-like object to schedule on */
19	  param: {
20	    value: number;
21	    setValueAtTime(value: number, time: number): void;
22	    linearRampToValueAtTime(value: number, time: number): void;
23	    cancelScheduledValues(startTime: number): void;
24	    cancelAndHoldAtTime?(startTime: number): void;
25	  };
26	  /** Parameter range for denormalization */
27	  range: ParameterRange;
28	};
29	
30	/**
31	 * Resolver function: given a lane's trackId and target,
32	 * returns the AudioParam and its range, or undefined if unresolvable.
33	 */
34	export type ParamResolver = (lane: AutomationLane) => ResolvedParam | undefined;
35	
36	export type AutomationScheduler = {
37	  /**
38	   * Schedule automation values for all lanes within a time window.
39	   * @param lanes - Active automation lanes to schedule
40	   * @param windowStart - Start of window in AudioContext time
41	   * @param windowEnd - End of window in AudioContext time
42	   * @param timeOffset - Offset: audioCtxTime = arrangementTime + timeOffset
43	   */
44	  scheduleWindow(
45	    lanes: readonly AutomationLane[],
46	    windowStart: number,
47	    windowEnd: number,
48	    timeOffset: number,
49	  ): void;
50	
51	  /** Cancel all scheduled automation values */
52	  cancelAll(): void;
53	};
54	
55	export function createAutomationScheduler(
56	  resolveParam: ParamResolver,
57	): AutomationScheduler {
58	  // Track params that have been scheduled for cancelAll
59	  const scheduledParams = new Set<ResolvedParam["param"]>();
60	
61	  return {
62	    scheduleWindow(lanes, windowStart, windowEnd, timeOffset) {
63	      // Guard: zero-length window has nothing to schedule
64	      if (windowEnd <= windowStart) return;
65	
66	      // Rebuild tracked params each window to avoid stale references
67	      const currentParams = new Set<ResolvedParam["param"]>();
68	
69	      for (const lane of lanes) {
70	        // Only schedule in read/touch mode when armed
71	        if (!lane.armed) continue;
72	        if (lane.mode === "write") continue;
73	        if (lane.points.length === 0) continue;
74	
75	        const resolved = resolveParam(lane);
76	        if (!resolved) continue;
77	
78	        const { param, range } = resolved;
79	        currentParams.add(param);
80	
81	        // Convert window to arrangement time
82	        const arrStart = windowStart - timeOffset;
83	        const arrEnd = windowEnd - timeOffset;
84	
85	        // Cancel previous scheduling (prefer cancelAndHoldAtTime for glitch-free transitions)
86	        if (param.cancelAndHoldAtTime) {
87	          param.cancelAndHoldAtTime(windowStart);
88	        } else {
89	          param.cancelScheduledValues(windowStart);
90	        }
91	
92	        // Schedule start value
93	        const startNorm = evaluateCurve(lane.points, arrStart);
94	        const startVal = denormalize(startNorm, range);
95	        param.setValueAtTime(startVal, windowStart);
96	
97	        // Schedule exact breakpoints within the window for sample-accurate playback
98	        const innerPoints = findPointsInRange(lane.points, arrStart, arrEnd);
99	        for (const pt of innerPoints) {
100	          const ctxTime = pt.time + timeOffset;
101	          const val = denormalize(pt.value, range);
102	          param.linearRampToValueAtTime(val, ctxTime);
103	        }
104	
105	        // Schedule end value
106	        const endNorm = evaluateCurve(lane.points, arrEnd);
107	        const endVal = denormalize(endNorm, range);
108	        param.linearRampToValueAtTime(endVal, windowEnd);
109	      }
110	
111	      // Replace tracked params to avoid unbounded growth from stale references
112	      scheduledParams.clear();
113	      for (const p of currentParams) scheduledParams.add(p);
114	    },
115	
116	    cancelAll() {
117	      for (const param of scheduledParams) {
118	        try {
119	          param.cancelScheduledValues(0);
120	        } catch {
121	          // Param may have been disconnected/disposed
122	        }
123	      }
124	      scheduledParams.clear();
125	    },
126	  };
127	}
