1	/**
2	 * Provider that creates the routing bridge.
3	 * Bridges the routing Zustand store to the live RoutingEngine audio graph.
4	 */
5	
6	import { createContext, useContext, useEffect, useRef, useState } from "react";
7	import { useAudioEngine } from "@audio/use-audio-engine";
8	import { createRoutingEngine, type RoutingEngine } from "./routing";
9	import { createRoutingBridge, type RoutingBridge } from "./routing-bridge";
10	import { useEffectsBridgeContext } from "@audio/effects/EffectsBridgeProvider";
11	
12	type RoutingBridgeContext = {
13	  readonly routing: RoutingEngine;
14	};
15	
16	const Ctx = createContext<RoutingBridgeContext | null>(null);
17	
18	export function RoutingBridgeProvider({
19	  children,
20	}: {
21	  children: React.ReactNode;
22	}): React.JSX.Element {
23	  const engine = useAudioEngine();
24	  const { mixer } = useEffectsBridgeContext();
25	
26	  const [value] = useState<{
27	    ctx: RoutingBridgeContext;
28	    bridge: RoutingBridge;
29	  }>(() => {
30	    const routing = createRoutingEngine(engine.ctx);
31	    const bridge = createRoutingBridge(routing, mixer);
32	    return { ctx: { routing }, bridge };
33	  });
34	
35	  const mountedRef = useRef(true);
36	  useEffect(() => {
37	    mountedRef.current = true;
38	    return () => {
39	      mountedRef.current = false;
40	      setTimeout(() => {
41	        if (!mountedRef.current) {
42	          value.bridge.dispose();
43	          value.ctx.routing.dispose();
44	        }
45	      }, 0);
46	    };
47	  }, [value]);
48	
49	  return <Ctx.Provider value={value.ctx}>{children}</Ctx.Provider>;
50	}
51	
52	export function useRoutingBridgeContext(): RoutingBridgeContext {
53	  const ctx = useContext(Ctx);
54	  if (ctx === null) {
55	    throw new Error(
56	      "useRoutingBridgeContext must be used within RoutingBridgeProvider",
57	    );
58	  }
59	  return ctx;
60	}
