1	/**
2	 * E13: Advanced Mixer Routing.
3	 * Send/return routing, bus/aux tracks, sidechain routing,
4	 * topological sort for render order, cycle detection.
5	 */
6	
7	import { RoutingGraph } from "./cycle-detection";
8	
9	export type SendRoute = {
10	  readonly sourceId: string;
11	  readonly busId: string;
12	  readonly sendGain: GainNode;
13	  level: number;
14	  preFader: boolean;
15	};
16	
17	export type BusTrack = {
18	  readonly id: string;
19	  readonly inputGain: GainNode;
20	  readonly faderGain: GainNode;
21	  readonly analyser: AnalyserNode;
22	  outputTarget: string; // "master" or another bus id
23	};
24	
25	export type SidechainRoute = {
26	  readonly sourceId: string;
27	  readonly targetId: string;
28	  readonly analyser: AnalyserNode;
29	};
30	
31	export type RoutingEngine = {
32	  createBus(id: string): BusTrack;
33	  removeBus(id: string): void;
34	  getBus(id: string): BusTrack | undefined;
35	  getAllBuses(): readonly BusTrack[];
36	  setBusOutput(busId: string, targetId: string): void;
37	  getMasterInput(): GainNode;
38	
39	  addSend(
40	    sourceId: string,
41	    busId: string,
42	    options?: { level?: number; preFader?: boolean },
43	  ): SendRoute;
44	  removeSend(sourceId: string, busId: string): void;
45	  setSendLevel(sourceId: string, busId: string, level: number): void;
46	  getSends(sourceId: string): readonly SendRoute[];
47	
48	  addSidechain(sourceId: string, targetId: string): SidechainRoute;
49	  removeSidechain(sourceId: string, targetId: string): void;
50	  getSidechains(targetId: string): readonly SidechainRoute[];
51	
52	  wouldCauseCycle(from: string, to: string): boolean;
53	  getRenderOrder(): readonly string[];
54	
55	  dispose(): void;
56	};
57	
58	function clamp(v: number, min: number, max: number): number {
59	  return Math.min(max, Math.max(min, v));
60	}
61	
62	/** Kahn's algorithm topological sort */
63	function topologicalSort(graph: RoutingGraph): readonly string[] {
64	  const nodes = graph.getNodes();
65	  if (nodes.length === 0) return [];
66	
67	  const inDegree = new Map<string, number>();
68	  for (const n of nodes) inDegree.set(n, 0);
69	
70	  for (const n of nodes) {
71	    for (const neighbor of graph.getEdges(n)) {
72	      inDegree.set(neighbor, (inDegree.get(neighbor) ?? 0) + 1);
73	    }
74	  }
75	
76	  const queue: string[] = [];
77	  for (const [n, deg] of inDegree) {
78	    if (deg === 0) queue.push(n);
79	  }
80	
81	  const result: string[] = [];
82	  while (queue.length > 0) {
83	    const current = queue.shift();
84	    if (current === undefined) break;
85	    result.push(current);
86	    for (const neighbor of graph.getEdges(current)) {
87	      const newDeg = (inDegree.get(neighbor) ?? 1) - 1;
88	      inDegree.set(neighbor, newDeg);
89	      if (newDeg === 0) queue.push(neighbor);
90	    }
91	  }
92	
93	  return result;
94	}
95	
96	export function createRoutingEngine(ctx: AudioContext): RoutingEngine {
97	  const buses = new Map<string, BusTrack>();
98	  const sends = new Map<string, SendRoute[]>(); // keyed by sourceId
99	  const sidechains: SidechainRoute[] = [];
100	  const graph = new RoutingGraph();
101	  const masterInput = ctx.createGain();
102	
103	  // Master node in graph
104	  graph.addNode("master");
105	
106	  function connectBusOutput(bus: BusTrack): void {
107	    bus.analyser.disconnect();
108	    if (bus.outputTarget === "master") {
109	      bus.analyser.connect(masterInput);
110	    } else {
111	      const targetBus = buses.get(bus.outputTarget);
112	      if (targetBus) {
113	        bus.analyser.connect(targetBus.inputGain);
114	      }
115	    }
116	  }
117	
118	  const engine: RoutingEngine = {
119	    createBus(id: string): BusTrack {
120	      const existing = buses.get(id);
121	      if (existing) return existing;
122	
123	      const inputGain = ctx.createGain();
124	      const faderGain = ctx.createGain();
125	      const analyser = ctx.createAnalyser();
126	
127	      inputGain.connect(faderGain);
128	      faderGain.connect(analyser);
129	      analyser.connect(masterInput);
130	
131	      const bus: BusTrack = {
132	        id,
133	        inputGain,
134	        faderGain,
135	        analyser,
136	        outputTarget: "master",
137	      };
138	      buses.set(id, bus);
139	
140	      graph.addNode(id);
141	      graph.addEdge(id, "master");
142	
143	      return bus;
144	    },
145	
146	    removeBus(id: string): void {
147	      const bus = buses.get(id);
148	      if (!bus) return;
149	
150	      // Re-route buses whose output targeted this bus back to master
151	      for (const other of buses.values()) {
152	        if (other.outputTarget === id) {
153	          graph.removeEdge(other.id, id);
154	          other.outputTarget = "master";
155	          graph.addEdge(other.id, "master");
156	          connectBusOutput(other);
157	        }
158	      }
159	
160	      // Remove sends FROM this bus (bus was a send source)
161	      const busSends = sends.get(id);
162	      if (busSends) {
163	        for (const send of busSends) {
164	          send.sendGain.disconnect();
165	          graph.removeEdge(id, send.busId);
166	        }
167	        sends.delete(id);
168	      }
169	
170	      // Remove all sends targeting this bus
171	      for (const [sourceId, trackSends] of sends.entries()) {
172	        const filtered = trackSends.filter((s) => {
173	          if (s.busId === id) {
174	            s.sendGain.disconnect();
175	            graph.removeEdge(sourceId, id);
176	            return false;
177	          }
178	          return true;
179	        });
180	        if (filtered.length === 0) {
181	          sends.delete(sourceId);
182	          // Prune orphaned source node (not a bus)
183	          if (!buses.has(sourceId)) graph.removeNode(sourceId);
184	        } else {
185	          sends.set(sourceId, filtered);
186	        }
187	      }
188	
189	      // Remove sidechains referencing this bus
190	      for (let i = sidechains.length - 1; i >= 0; i--) {
191	        const sc = sidechains[i];
192	        if (sc && (sc.sourceId === id || sc.targetId === id)) {
193	          sc.analyser.disconnect();
194	          sidechains.splice(i, 1);
195	        }
196	      }
197	
198	      bus.inputGain.disconnect();
199	      bus.faderGain.disconnect();
200	      bus.analyser.disconnect();
201	      buses.delete(id);
202	      graph.removeNode(id);
203	    },
204	
205	    getBus(id: string): BusTrack | undefined {
206	      return buses.get(id);
207	    },
208	
209	    getAllBuses(): readonly BusTrack[] {
210	      return [...buses.values()];
211	    },
212	
213	    setBusOutput(busId: string, targetId: string): void {
214	      const bus = buses.get(busId);
215	      if (!bus) return;
216	
217	      if (targetId !== "master" && !buses.has(targetId)) {
218	        throw new Error(`Bus output target not found: ${targetId}`);
219	      }
220	
221	      if (graph.wouldCauseCycle(busId, targetId)) {
222	        throw new Error(`Routing cycle detected: ${busId} -> ${targetId}`);
223	      }
224	
225	      graph.removeEdge(busId, bus.outputTarget);
226	      bus.outputTarget = targetId;
227	      graph.addEdge(busId, targetId);
228	      connectBusOutput(bus);
229	    },
230	
231	    getMasterInput(): GainNode {
232	      return masterInput;
233	    },
234	
235	    addSend(
236	      sourceId: string,
237	      busId: string,
238	      options?: { level?: number; preFader?: boolean },
239	    ): SendRoute {
240	      const trackSends = sends.get(sourceId) ?? [];
241	
242	      // Prevent duplicate
243	      const existing = trackSends.find((s) => s.busId === busId);
244	      if (existing) return existing;
245	
246	      const bus = buses.get(busId);
247	      if (!bus) throw new Error(`Bus not found: ${busId}`);
248	
249	      if (graph.wouldCauseCycle(sourceId, busId)) {
250	        throw new Error(`Routing cycle detected: ${sourceId} -> ${busId}`);
251	      }
252	
253	      const level = clamp(options?.level ?? 1, 0, 1);
254	      const preFader = options?.preFader ?? false;
255	
256	      const sendGain = ctx.createGain();
257	      sendGain.gain.value = level;
258	      sendGain.connect(bus.inputGain);
259	
260	      const send: SendRoute = {
261	        sourceId,
262	        busId,
263	        sendGain,
264	        level,
265	        preFader,
266	      };
267	
268	      trackSends.push(send);
269	      sends.set(sourceId, trackSends);
270	
271	      graph.addNode(sourceId);
272	      graph.addEdge(sourceId, busId);
273	
274	      return send;
275	    },
276	
277	    removeSend(sourceId: string, busId: string): void {
278	      const trackSends = sends.get(sourceId);
279	      if (!trackSends) return;
280	
281	      const idx = trackSends.findIndex((s) => s.busId === busId);
282	      if (idx === -1) return;
283	
284	      const removed = trackSends[idx];
285	      if (!removed) return;
286	      removed.sendGain.disconnect();
287	      trackSends.splice(idx, 1);
288	
289	      graph.removeEdge(sourceId, busId);
290	
291	      if (trackSends.length === 0) {
292	        sends.delete(sourceId);
293	        // Prune orphaned source node (not a bus)
294	        if (!buses.has(sourceId)) graph.removeNode(sourceId);
295	      }
296	    },
297	
298	    setSendLevel(sourceId: string, busId: string, level: number): void {
299	      const trackSends = sends.get(sourceId);
300	      if (!trackSends) return;
301	
302	      const send = trackSends.find((s) => s.busId === busId);
303	      if (!send) return;
304	
305	      const clamped = clamp(level, 0, 1);
306	      send.level = clamped;
307	      send.sendGain.gain.value = clamped;
308	    },
309	
310	    getSends(sourceId: string): readonly SendRoute[] {
311	      return sends.get(sourceId) ?? [];
312	    },
313	
314	    addSidechain(sourceId: string, targetId: string): SidechainRoute {
315	      const existing = sidechains.find(
316	        (sc) => sc.sourceId === sourceId && sc.targetId === targetId,
317	      );
318	      if (existing) return existing;
319	
320	      const analyser = ctx.createAnalyser();
321	      const sc: SidechainRoute = { sourceId, targetId, analyser };
322	      sidechains.push(sc);
323	      return sc;
324	    },
325	
326	    removeSidechain(sourceId: string, targetId: string): void {
327	      const idx = sidechains.findIndex(
328	        (sc) => sc.sourceId === sourceId && sc.targetId === targetId,
329	      );
330	      if (idx === -1) return;
331	      const removed = sidechains[idx];
332	      if (!removed) return;
333	      removed.analyser.disconnect();
334	      sidechains.splice(idx, 1);
335	    },
336	
337	    getSidechains(targetId: string): readonly SidechainRoute[] {
338	      return sidechains.filter((sc) => sc.targetId === targetId);
339	    },
340	
341	    wouldCauseCycle(from: string, to: string): boolean {
342	      return graph.wouldCauseCycle(from, to);
343	    },
344	
345	    getRenderOrder(): readonly string[] {
346	      return topologicalSort(graph).filter((n) => n !== "master");
347	    },
348	
349	    dispose(): void {
350	      for (const trackSends of sends.values()) {
351	        for (const send of trackSends) {
352	          send.sendGain.disconnect();
353	        }
354	      }
355	      sends.clear();
356	
357	      for (const sc of sidechains) {
358	        sc.analyser.disconnect();
359	      }
360	      sidechains.length = 0;
361	
362	      for (const bus of buses.values()) {
363	        bus.inputGain.disconnect();
364	        bus.faderGain.disconnect();
365	        bus.analyser.disconnect();
366	      }
367	      buses.clear();
368	
369	      graph.clear();
370	      masterInput.disconnect();
371	    },
372	  };
373	
374	  return engine;
375	}
376

