1	/**
2	 * Sample-based drum kit engine.
3	 * Plays one-shot AudioBuffers through BiquadFilter + GainNode envelope.
4	 * Per-instrument Tone/Decay/Tune/Volume. Hi-hat mutual exclusivity.
5	 *
6	 * Uses native Web Audio nodes (per lesson L9ed0990ebe98f667).
7	 */
8	
9	import type { MixerEngine } from "@audio/mixer/types";
10	import type {
11	  DrumInstrumentId,
12	  DrumInstrumentParams,
13	  DrumKit,
14	} from "./drum-types";
15	import { DEFAULT_INSTRUMENT_PARAMS, PARAM_RANGES } from "./drum-types";
16	
17	function clampParam(key: keyof DrumInstrumentParams, value: number): number {
18	  const range = PARAM_RANGES[key];
19	  return Math.min(range.max, Math.max(range.min, value));
20	}
21	
22	type ActiveVoice = {
23	  source: AudioBufferSourceNode;
24	  gain: GainNode;
25	};
26	
27	export function createDrumKit(
28	  ctx: AudioContext,
29	  samples: Map<DrumInstrumentId, AudioBuffer>,
30	): DrumKit {
31	  const output = ctx.createGain();
32	  const params = new Map<DrumInstrumentId, DrumInstrumentParams>();
33	
34	  // Clone defaults
35	  for (const [id, defaults] of Object.entries(DEFAULT_INSTRUMENT_PARAMS)) {
36	    params.set(id as DrumInstrumentId, { ...defaults });
37	  }
38	
39	  // Track active open hi-hat voices for mutual exclusivity (primary + flam)
40	  let activeOH: ActiveVoice | null = null;
41	  let activeOHFlam: ActiveVoice | null = null;
42	
43	  function triggerOnce(
44	    instrumentId: DrumInstrumentId,
45	    time: number,
46	    velocity: number,
47	  ): ActiveVoice | null {
48	    const buffer = samples.get(instrumentId);
49	    if (!buffer) return null;
50	
51	    const p = params.get(instrumentId);
52	    if (!p) return null;
53	
54	    // AudioBufferSourceNode — sample playback
55	    const source = ctx.createBufferSource();
56	    source.buffer = buffer;
57	    source.playbackRate.setValueAtTime(p.tune, time);
58	
59	    // BiquadFilter — tone control (lowpass)
60	    const filter = ctx.createBiquadFilter();
61	    filter.type = "lowpass";
62	    filter.frequency.setValueAtTime(p.tone, time);
63	
64	    // GainNode — volume envelope with decay
65	    const gain = ctx.createGain();
66	    // Clamp velocity to [0,1] and ensure peakGain > 0 for exponentialRamp
67	    const peakGain = Math.max(0.001, p.volume * Math.min(1, velocity));
68	    gain.gain.setValueAtTime(peakGain, time);
69	    gain.gain.exponentialRampToValueAtTime(0.001, time + p.decay);
70	
71	    // Chain: source -> filter -> gain -> output
72	    source.connect(filter);
73	    filter.connect(gain);
74	    gain.connect(output);
75	
76	    source.start(time);
77	    source.stop(time + p.decay + 0.01);
78	
79	    // Clean up on ended
80	    source.addEventListener("ended", () => {
81	      source.disconnect();
82	      filter.disconnect();
83	      gain.disconnect();
84	      // Clear stale OH reference when voice decays naturally
85	      if (instrumentId === "oh") {
86	        if (activeOH?.source === source) activeOH = null;
87	        if (activeOHFlam?.source === source) activeOHFlam = null;
88	      }
89	    });
90	
91	    return { source, gain };
92	  }
93	
94	  const kit: DrumKit = {
95	    trigger(
96	      instrumentId: DrumInstrumentId,
97	      time: number,
98	      velocity: number,
99	      flamMs?: number,
100	    ): void {
101	      // Hi-hat mutual exclusivity: CH cuts OH (primary + flam)
102	      if (instrumentId === "ch") {
103	        for (const voice of [activeOH, activeOHFlam]) {
104	          if (voice) {
105	            try {
106	              voice.gain.gain.cancelScheduledValues(time);
107	              voice.gain.gain.setValueAtTime(0, time);
108	              voice.source.stop(time + 0.001);
109	            } catch {
110	              // Source may already be stopped
111	            }
112	          }
113	        }
114	        activeOH = null;
115	        activeOHFlam = null;
116	      }
117	
118	      const voice = triggerOnce(instrumentId, time, velocity);
119	
120	      // Track open hi-hat voice
121	      if (instrumentId === "oh" && voice) {
122	        activeOH = voice;
123	      }
124	
125	      // Flam: trigger a second quieter hit offset by flamMs
126	      if (flamMs !== undefined && flamMs > 0) {
127	        const flamVoice = triggerOnce(
128	          instrumentId,
129	          time + flamMs / 1000,
130	          velocity * 0.7,
131	        );
132	        if (instrumentId === "oh" && flamVoice) {
133	          activeOHFlam = flamVoice;
134	        }
135	      }
136	    },
137	
138	    setParam(
139	      instrumentId: DrumInstrumentId,
140	      key: keyof DrumInstrumentParams,
141	      value: number,
142	    ): void {
143	      const p = params.get(instrumentId);
144	      if (!p) return;
145	      (p as Record<string, number>)[key] = clampParam(key, value);
146	    },
147	
148	    connectToMixer(mixer: MixerEngine, trackId: string): void {
149	      const strip = mixer.getOrCreateStrip(trackId);
150	      output.connect(strip.inputGain);
151	    },
152	
153	    disconnectFromMixer(mixer: MixerEngine, trackId: string): void {
154	      const strip = mixer.getOrCreateStrip(trackId);
155	      output.disconnect(strip.inputGain);
156	    },
157	
158	    dispose(): void {
159	      output.disconnect();
160	    },
161	  };
162	
163	  return kit;
164	}
