145	    createBufferSource: mockBufferSource,
146	    createBuffer(
147	      channels: number,
148	      length: number,
149	      sampleRate: number,
150	    ): AudioBuffer {
151	      const channelData: Float32Array[] = [];
152	      for (let i = 0; i < channels; i++) {
153	        channelData.push(new Float32Array(length));
154	      }
155	      return {
156	        numberOfChannels: channels,
157	        length,
158	        sampleRate,
159	        duration: length / sampleRate,
160	        getChannelData(c: number): Float32Array {
161	          const data = channelData[c];
162	          if (data === undefined) throw new Error(`No channel ${String(c)}`);
163	          return data;
164	        },
165	        copyToChannel(source: Float32Array, c: number): void {
166	          const data = channelData[c];
167	          if (data === undefined) throw new Error(`No channel ${String(c)}`);
168	          data.set(source);
169	        },
170	        copyFromChannel(dest: Float32Array, c: number): void {
171	          const data = channelData[c];
172	          if (data === undefined) throw new Error(`No channel ${String(c)}`);
173	          dest.set(data.subarray(0, dest.length));
174	        },
175	      } as unknown as AudioBuffer;
176	    },
177	    audioWorklet: {
178	      addModule: vi.fn().mockResolvedValue(undefined),
179	    },
180	    resume: vi.fn().mockResolvedValue(undefined),
181	    close: vi.fn().mockResolvedValue(undefined),
182	    _advanceTime(seconds: number): void {
183	      _currentTime += seconds;
184	    },
185	  };
186	
187	  return ctx as unknown as AudioContext;
188	}
