190	/** Advance the mock AudioContext's currentTime */
191	export function advanceTime(ctx: AudioContext, seconds: number): void {
192	  (ctx as unknown as { _advanceTime: (s: number) => void })._advanceTime(
193	    seconds,
194	  );
