1	/**
2	 * Integration test: verifies the full automation bridge
3	 * from store data -> AutomationScheduler -> AudioParam values.
4	 *
5	 * This test proves that the automation system works end-to-end:
6	 * store adds lane+points -> scheduler evaluates curve -> AudioParam receives values.
7	 */
8	
9	import { describe, it, expect, vi, beforeEach } from "vitest";
10	import { useAutomationStore } from "@state/automation";
11	import { createAutomationScheduler } from "@audio/automation/automation-scheduler";
12	import type { ParamResolver } from "@audio/automation/automation-scheduler";
13	import { _resetLaneCounter } from "@audio/automation/automation-types";
14	
15	type MockParam = {
16	  value: number;
17	  setValueAtTime: ReturnType<typeof vi.fn>;
18	  linearRampToValueAtTime: ReturnType<typeof vi.fn>;
19	  cancelScheduledValues: ReturnType<typeof vi.fn>;
20	  cancelAndHoldAtTime: ReturnType<typeof vi.fn>;
21	};
22	
23	function mockAudioParam(): MockParam {
24	  return {
25	    value: 0,
26	    setValueAtTime: vi.fn(),
27	    linearRampToValueAtTime: vi.fn(),
28	    cancelScheduledValues: vi.fn(),
29	    cancelAndHoldAtTime: vi.fn(),
30	  };
31	}
32	
33	function getLaneId(trackId: string): string {
34	  const lane = useAutomationStore.getState().getLanes(trackId)[0];
35	  if (lane === undefined) throw new Error("lane not found");
36	  return lane.id;
37	}
38	
39	describe("Automation bridge: store -> scheduler -> AudioParam", () => {
40	  beforeEach(() => {
41	    useAutomationStore.setState({ lanes: {} });
42	    _resetLaneCounter();
43	  });
44	
45	  it("applies store automation to AudioParam during scheduling", () => {
46	    const store = useAutomationStore.getState();
47	
48	    // 1. Add a volume lane for track-1
49	    store.addLane("track-1", { type: "mixer", param: "volume" });
50	    const laneId = getLaneId("track-1");
51	
52	    // 2. Add automation points: volume ramp from 0.0 to 1.0 over 10 seconds
53	    store.addPoint("track-1", laneId, {
54	      id: "p1",
55	      time: 0,
56	      value: 0,
57	      interpolation: "linear",
58	      curve: 0,
59	    });
60	    store.addPoint("track-1", laneId, {
61	      id: "p2",
62	      time: 10,
63	      value: 1,
64	      interpolation: "linear",
65	      curve: 0,
66	    });
67	
68	    // 3. Set up mock AudioParam (simulating a mixer fader gain node)
69	    const param = mockAudioParam();
70	    const volumeRange = { min: 0, max: 2 }; // fader range: 0 to 2x
71	
72	    // 4. Create resolver that maps the lane to our mock param
73	    const resolver: ParamResolver = (l) => {
74	      if (l.target.type === "mixer" && l.target.param === "volume") {
75	        return { param, range: volumeRange };
76	      }
77	      return undefined;
78	    };
79	
80	    // 5. Create scheduler and schedule a window
81	    const scheduler = createAutomationScheduler(resolver);
82	    const lanes = useAutomationStore.getState().getLanes("track-1");
83	
84	    // Schedule window: arrangement time 0-2, offset 0
85	    scheduler.scheduleWindow(lanes, 0, 2, 0);
86	
87	    // 6. Verify AudioParam received correct values
88	    expect(param.cancelAndHoldAtTime).toHaveBeenCalledWith(0);
89	    expect(param.setValueAtTime).toHaveBeenCalled();
90	
91	    // At t=0, normalized value is 0.0, denormalized = 0.0 * (2-0) + 0 = 0.0
92	    const startCall = param.setValueAtTime.mock.calls[0] as [number, number];
93	    expect(startCall[0]).toBeCloseTo(0.0, 2);
94	    expect(startCall[1]).toBe(0); // window start
95	
96	    // At t=2, normalized value is 0.2 (linear interp 2/10), denormalized = 0.2 * 2 = 0.4
97	    const endRamps = param.linearRampToValueAtTime.mock.calls as [
98	      number,
99	      number,
100	    ][];
101	    const endRamp = endRamps[endRamps.length - 1];
102	    expect(endRamp?.[0]).toBeCloseTo(0.4, 2);
103	    expect(endRamp?.[1]).toBe(2); // window end
104	  });
105	
106	  it("ignores unarmed lanes", () => {
107	    const store = useAutomationStore.getState();
108	    store.addLane("track-1", { type: "mixer", param: "volume" });
109	    const laneId = getLaneId("track-1");
110	
111	    store.addPoint("track-1", laneId, {
112	      id: "p1",
113	      time: 0,
114	      value: 0.5,
115	      interpolation: "linear",
116	      curve: 0,
117	    });
118	
119	    // Disarm the lane
120	    store.setArmed("track-1", laneId, false);
121	
122	    const param = mockAudioParam();
123	    const resolver: ParamResolver = (l) => {
124	      if (l.target.type === "mixer" && l.target.param === "volume") {
125	        return { param, range: { min: 0, max: 2 } };
126	      }
127	      return undefined;
128	    };
129	
130	    const scheduler = createAutomationScheduler(resolver);
131	    const lanes = useAutomationStore.getState().getLanes("track-1");
132	    scheduler.scheduleWindow(lanes, 0, 1, 0);
133	
134	    // Should NOT schedule anything because lane is disarmed
135	    expect(param.setValueAtTime).not.toHaveBeenCalled();
136	  });
137	
138	  it("handles pan automation with -1..1 range", () => {
139	    const store = useAutomationStore.getState();
140	    store.addLane("track-1", { type: "mixer", param: "pan" });
141	    const laneId = getLaneId("track-1");
142	
143	    // Center pan (0.5 normalized -> 0.0 actual)
144	    store.addPoint("track-1", laneId, {
145	      id: "p1",
146	      time: 0,
147	      value: 0.5,
148	      interpolation: "linear",
149	      curve: 0,
150	    });
151	
152	    const param = mockAudioParam();
153	    const resolver: ParamResolver = (l) => {
154	      if (l.target.type === "mixer" && l.target.param === "pan") {
155	        return { param, range: { min: -1, max: 1 } };
156	      }
157	      return undefined;
158	    };
159	
160	    const scheduler = createAutomationScheduler(resolver);
161	    const lanes = useAutomationStore.getState().getLanes("track-1");
162	    scheduler.scheduleWindow(lanes, 0, 1, 0);
163	
164	    expect(param.setValueAtTime).toHaveBeenCalled();
165	    const startCall = param.setValueAtTime.mock.calls[0] as [number, number];
166	    // 0.5 normalized with range -1..1 = -1 + 0.5 * 2 = 0.0
167	    expect(startCall[0]).toBeCloseTo(0.0, 2);
168	  });
169	
170	  it("cleans up with cancelAll", () => {
171	    const store = useAutomationStore.getState();
172	    store.addLane("track-1", { type: "mixer", param: "volume" });
173	    const laneId = getLaneId("track-1");
174	
175	    store.addPoint("track-1", laneId, {
176	      id: "p1",
177	      time: 0,
178	      value: 0.5,
179	      interpolation: "linear",
180	      curve: 0,
181	    });
182	
183	    const param = mockAudioParam();
184	    const resolver: ParamResolver = () => ({
185	      param,
186	      range: { min: 0, max: 2 },
187	    });
188	
189	    const scheduler = createAutomationScheduler(resolver);
190	    const lanes = useAutomationStore.getState().getLanes("track-1");
191	    scheduler.scheduleWindow(lanes, 0, 1, 0);
192	    scheduler.cancelAll();
193	
194	    expect(param.cancelScheduledValues).toHaveBeenCalled();
195	  });
196	});
