137	      engine.createBus("bus-1");
138	      engine.addSend("track-1", "bus-1", { level: 0.3 });
139	      engine.setSendLevel("track-1", "bus-1", 0.8);
140	      const sends = engine.getSends("track-1");
141	      expect(sends[0]?.level).toBeCloseTo(0.8);
142	    });
143	
144	    it("clamps send level to 0..1", () => {
145	      engine.createBus("bus-1");
146	      engine.addSend("track-1", "bus-1");
147	      engine.setSendLevel("track-1", "bus-1", 2.0);
148	      const sends = engine.getSends("track-1");
149	      expect(sends[0]?.level).toBe(1);
150	    });
151	
152	    it("removes a send", () => {
153	      engine.createBus("bus-1");
154	      engine.addSend("track-1", "bus-1");
155	      engine.removeSend("track-1", "bus-1");
156	      expect(engine.getSends("track-1")).toHaveLength(0);
157	    });
158	
159	    it("lists sends for a track", () => {
160	      engine.createBus("bus-1");
161	      engine.createBus("bus-2");
162	      engine.addSend("track-1", "bus-1");
163	      engine.addSend("track-1", "bus-2");
164	      expect(engine.getSends("track-1")).toHaveLength(2);
165	    });
166	
167	    it("prevents duplicate sends to same bus", () => {
168	      engine.createBus("bus-1");
169	      engine.addSend("track-1", "bus-1");
170	      engine.addSend("track-1", "bus-1");
171	      expect(engine.getSends("track-1")).toHaveLength(1);
172	    });
173	
174	    it("removes all sends when bus is removed", () => {
175	      engine.createBus("bus-1");
176	      engine.addSend("track-1", "bus-1");
177	      engine.addSend("track-2", "bus-1");
178	      engine.removeBus("bus-1");
179	      expect(engine.getSends("track-1")).toHaveLength(0);
180	      expect(engine.getSends("track-2")).toHaveLength(0);
181	    });
182	
183	    it("re-routes dependent buses to master when bus is removed", () => {
184	      engine.createBus("bus-1");
185	      engine.createBus("bus-2");
186	      engine.setBusOutput("bus-1", "bus-2");
187	      expect(engine.getBus("bus-1")?.outputTarget).toBe("bus-2");
188	      engine.removeBus("bus-2");
189	      expect(engine.getBus("bus-1")?.outputTarget).toBe("master");
190	    });
191	
192	    it("removes sends sourced from the removed bus", () => {
193	      engine.createBus("bus-1");
194	      engine.createBus("bus-2");
195	      engine.addSend("bus-1", "bus-2");
196	      expect(engine.getSends("bus-1")).toHaveLength(1);
197	      engine.removeBus("bus-1");
198	      expect(engine.getSends("bus-1")).toHaveLength(0);
199	    });
200	
201	    it("cleans up graph edges for sends sourced from removed bus", () => {
202	      engine.createBus("bus-1");
203	      engine.createBus("bus-2");
204	      engine.addSend("bus-1", "bus-2");
205	      engine.removeBus("bus-1");
206	      // bus-2 should still be reachable but bus-1 gone
207	      expect(engine.getBus("bus-1")).toBeUndefined();
208	      expect(engine.getBus("bus-2")).toBeDefined();
209	      expect(engine.getRenderOrder()).not.toContain("bus-1");
210	    });
211	
212	    it("removes sidechains referencing removed bus", () => {
213	      engine.createBus("bus-1");
214	      engine.addSidechain("bus-1", "track-1");
215	      engine.addSidechain("track-2", "bus-1");
216	      engine.removeBus("bus-1");
217	      expect(engine.getSidechains("track-1")).toHaveLength(0);
218	      expect(engine.getSidechains("bus-1")).toHaveLength(0);
219	    });
220	  });
221	
222	  describe("sidechain routing", () => {
223	    it("creates a sidechain route", () => {
224	      const sc = engine.addSidechain("track-1", "track-2");
225	      expect(sc.sourceId).toBe("track-1");
226	      expect(sc.targetId).toBe("track-2");
227	    });
228	
229	    it("returns existing sidechain for same pair", () => {
230	      const a = engine.addSidechain("track-1", "track-2");
231	      const b = engine.addSidechain("track-1", "track-2");
232	      expect(a).toBe(b);
233	    });
234	
235	    it("removes a sidechain route", () => {
236	      engine.addSidechain("track-1", "track-2");
237	      engine.removeSidechain("track-1", "track-2");
238	      expect(engine.getSidechains("track-2")).toHaveLength(0);
239	    });
240	
241	    it("lists sidechains targeting a track", () => {
242	      engine.addSidechain("track-1", "track-3");
243	      engine.addSidechain("track-2", "track-3");
244	      expect(engine.getSidechains("track-3")).toHaveLength(2);
245	    });
246	  });
247	
248	  describe("cycle detection with sends and buses", () => {
249	    it("rejects send that would create cycle", () => {
250	      engine.createBus("bus-1");
251	      // bus-1 outputs to master, so track -> bus-1 is fine
252	      engine.addSend("track-1", "bus-1");
253	
254	      // Now if bus-1 routes back to track-1, that's a cycle
255	      // (not possible with sends to buses, but bus-to-bus routing could)
256	      expect(engine.wouldCauseCycle("bus-1", "track-1")).toBe(true);
257	    });
258	
259	    it("allows valid send routing", () => {
260	      engine.createBus("bus-1");
261	      expect(engine.wouldCauseCycle("track-1", "bus-1")).toBe(false);
262	    });
263	
264	    it("detects cycle in bus-to-bus routing", () => {
265	      engine.createBus("bus-1");
266	      engine.createBus("bus-2");
267	      engine.addSend("bus-1", "bus-2");
268	      // bus-2 -> bus-1 would create cycle
269	      expect(engine.wouldCauseCycle("bus-2", "bus-1")).toBe(true);
270	    });
271	
272	    it("addSend throws on cycle", () => {
273	      engine.createBus("bus-1");
274	      engine.createBus("bus-2");
275	      engine.addSend("bus-1", "bus-2");
276	      expect(() => {
277	        engine.addSend("bus-2", "bus-1");
278	      }).toThrow(/cycle/i);
279	    });
280	  });
281	
282	  describe("topological sort", () => {
283	    it("returns render order for simple track -> master", () => {
284	      engine.createBus("bus-1");
285	      engine.addSend("track-1", "bus-1");
286	      const order = engine.getRenderOrder();
287	      // track-1 must come before bus-1
288	      const trackIdx = order.indexOf("track-1");
289	      const busIdx = order.indexOf("bus-1");
290	      expect(trackIdx).toBeLessThan(busIdx);
291	    });
292	
293	    it("updates render order when routing changes", () => {
294	      engine.createBus("bus-1");
295	      engine.createBus("bus-2");
296	      engine.addSend("track-1", "bus-1");
297	      engine.addSend("bus-1", "bus-2");
298	      const order = engine.getRenderOrder();
299	      const t1 = order.indexOf("track-1");
300	      const b1 = order.indexOf("bus-1");
301	      const b2 = order.indexOf("bus-2");
302	      expect(t1).toBeLessThan(b1);
303	      expect(b1).toBeLessThan(b2);
304	    });
305	
306	    it("returns empty order for empty graph", () => {
307	      expect(engine.getRenderOrder()).toEqual([]);
308	    });
309	  });
310	
311	  describe("bus output routing", () => {
312	    it("routes bus to master by default", () => {
313	      const bus = engine.createBus("bus-1");
314	      expect(bus.outputTarget).toBe("master");
315	    });
316	
317	    it("routes bus to another bus", () => {
318	      engine.createBus("bus-1");
319	      engine.createBus("bus-2");
320	      engine.setBusOutput("bus-1", "bus-2");
321	      const bus = engine.getBus("bus-1");
322	      expect(bus?.outputTarget).toBe("bus-2");
323	    });
324	
325	    it("rejects bus output that would create cycle", () => {
326	      engine.createBus("bus-1");
327	      engine.createBus("bus-2");
328	      engine.addSend("bus-1", "bus-2");
329	      // bus-2 -> bus-1 would cycle
330	      expect(() => {
331	        engine.setBusOutput("bus-2", "bus-1");
332	      }).toThrow(/cycle/i);
333	    });
334	
335	    it("rejects bus output to unknown target", () => {
336	      engine.createBus("bus-1");
337	      expect(() => {
338	        engine.setBusOutput("bus-1", "nonexistent");
339	      }).toThrow(/not found/i);
340	    });
341	  });
342	
343	  describe("dispose", () => {
344	    it("cleans up all buses and sends", () => {
345	      engine.createBus("bus-1");
346	      engine.addSend("track-1", "bus-1");
347	      engine.addSidechain("track-1", "track-2");
348	      engine.dispose();
349	      expect(engine.getAllBuses()).toHaveLength(0);
350	      expect(engine.getSends("track-1")).toHaveLength(0);
351	      expect(engine.getSidechains("track-2")).toHaveLength(0);
352	    });
353	
354	    it("clears routing graph on dispose", () => {
355	      engine.createBus("bus-1");
356	      engine.addSend("track-1", "bus-1");
357	      engine.dispose();
358	      expect(engine.getRenderOrder()).toEqual([]);
359	    });
360	  });
361	
362	  describe("removeSend node pruning", () => {
363	    it("prunes orphaned track node from graph after last send removed", () => {
364	      engine.createBus("bus-1");
365	      engine.addSend("track-1", "bus-1");
366	      engine.removeSend("track-1", "bus-1");
367	      // track-1 should not appear in render order
368	      expect(engine.getRenderOrder()).not.toContain("track-1");
369	    });
370	
371	    it("keeps bus node in graph after its sends are removed", () => {
372	      engine.createBus("bus-1");
373	      engine.createBus("bus-2");
374	      engine.addSend("bus-1", "bus-2");
375	      engine.removeSend("bus-1", "bus-2");
376	      // bus-1 should still be in graph (it's a bus, not just a send source)
377	      expect(engine.getRenderOrder()).toContain("bus-1");
378	    });
379	  });
380	});
