}

export function makeAutomationPoint(
  overrides: Partial<AutomationPoint> = {},
): AutomationPoint {
  return {
    id: nextId("pt"),
    time: 0,
    value: 0.5,
    interpolation: "linear",
    curve: 0,
    ...overrides,
  };
}

export function makeEffectSlot(
  overrides: Partial<EffectSlotState> = {},
): EffectSlotState {
  return {
    id: nextId("fx"),
