        const allLanes = useAutomationStore.getState().lanes;
        const lanes = Object.values(allLanes).flat();
        autoSched.scheduleWindow(lanes, windowStart, windowEnd, timeOffset);
      },
    );
    schedulerRef.current = scheduler;

    return () => {
      scheduler.stop();
      autoSched.cancelAll();
      met.dispose();
      clock.dispose();
      clockRef.current = null;
      schedulerRef.current = null;
      metronomeRef.current = null;
      autoSchedulerRef.current = null;
      sabRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- init once
  }, [engine]);

  const play = useCallback((): void => {
    const clock = clockRef.current;
    const scheduler = schedulerRef.current;
    if (clock === null || scheduler === null) return;
    if (clock.state === "playing") return;

    clock.play();
    scheduler.start();
    storePlay();
  }, [storePlay]);

  const pause = useCallback((): void => {
    const clock = clockRef.current;
    const scheduler = schedulerRef.current;
    if (clock === null || scheduler === null) return;
    if (clock.state !== "playing") return;

    clock.pause();
    scheduler.stop();
    autoSchedulerRef.current?.cancelAll();
    storeSetCursor(clock.getCursorSeconds());
    storePause();
  }, [storePause, storeSetCursor]);

  const stop = useCallback((): void => {
    const clock = clockRef.current;
    const scheduler = schedulerRef.current;
    const met = metronomeRef.current;
    if (clock === null || scheduler === null) return;

    // INV-6: Guarantee silence within 10ms
    met?.silence();
    clock.stop();
    scheduler.stop();
    autoSchedulerRef.current?.cancelAll();
    storeSetCursor(0);
    storeStop();
  }, [storeStop, storeSetCursor]);

  const seek = useCallback(
    (seconds: number): void => {
      const clock = clockRef.current;
      if (clock === null) return;

      clock.seek(seconds);
      schedulerRef.current?.sync();
      storeSetCursor(clock.getCursorSeconds());
    },
    [storeSetCursor],
  );

  const setBpm = useCallback(
    (newBpm: number): void => {
      const clock = clockRef.current;
      if (clock === null) return;

      clock.setBpm(newBpm);
      storeSetBpm(newBpm);
    },
    [storeSetBpm],
  );

  const setMetronomeEnabled = useCallback((on: boolean): void => {
    metronomeRef.current?.setEnabled(on);
  }, []);

  const getTransportSAB = useCallback((): SharedArrayBuffer | null => {
    return sabRef.current?.transport ?? null;
  }, []);

  const getClock = useCallback((): TransportClock | null => {
    return clockRef.current;
  }, []);

  const setParamResolver = useCallback((resolver: ParamResolver): void => {
    paramResolverRef.current = resolver;
  }, []);

  return {
    play,
    pause,
    stop,
    seek,
    setBpm,
    setMetronomeEnabled,
    getTransportSAB,
    getClock,
    setParamResolver,
  };
}

/**
 * Context consumer hook. Must be used within a TransportProvider.
 */
export function useTransport(): UseTransportReturn {
  const transport = useContext(TransportCtx);
  if (transport === null) {
    throw new Error("useTransport must be used within TransportProvider");
  }
  return transport;
}

