    expect(screen.getByText("Audio Track")).toBeInTheDocument();
    expect(screen.getByText("Instrument Track")).toBeInTheDocument();
    expect(screen.getByText("Drum Track")).toBeInTheDocument();
  });

  it("adds an audio track when 'Audio Track' is clicked", async () => {
    const { TransportBar } = await import("@ui/transport/TransportBar");
    render(<TransportBar />);
    fireEvent.click(screen.getByLabelText("Add Track"));
    fireEvent.click(screen.getByText("Audio Track"));

    const tracks = useDawStore.getState().tracks;
    expect(tracks).toHaveLength(1);
    expect(tracks[0]?.type).toBe("audio");
  });

  it("adds an instrument track when 'Instrument Track' is clicked", async () => {
    const { TransportBar } = await import("@ui/transport/TransportBar");
    render(<TransportBar />);
    fireEvent.click(screen.getByLabelText("Add Track"));
    fireEvent.click(screen.getByText("Instrument Track"));

    const tracks = useDawStore.getState().tracks;
    expect(tracks).toHaveLength(1);
    expect(tracks[0]?.type).toBe("instrument");
  });

  it("adds a drum track when 'Drum Track' is clicked", async () => {
    const { TransportBar } = await import("@ui/transport/TransportBar");
    render(<TransportBar />);
    fireEvent.click(screen.getByLabelText("Add Track"));
    fireEvent.click(screen.getByText("Drum Track"));

    const tracks = useDawStore.getState().tracks;
    expect(tracks).toHaveLength(1);
    expect(tracks[0]?.type).toBe("drum");
  });

  it("selects the newly created track", async () => {
    const { TransportBar } = await import("@ui/transport/TransportBar");
    render(<TransportBar />);
    fireEvent.click(screen.getByLabelText("Add Track"));
    fireEvent.click(screen.getByText("Drum Track"));

    const selectedIds = useDawStore.getState().selectedTrackIds;
    const tracks = useDawStore.getState().tracks;
    expect(selectedIds).toContain(tracks[0]?.id);
  });
});

// -- InstrumentPanel tests --
describe("InstrumentPanel", () => {
  beforeEach(() => {
    useDawStore.setState({ tracks: [], selectedTrackIds: [] });
  });

  it("shows 'Select a track' when nothing is selected", async () => {
    const { InstrumentPanel } = await import("@ui/panels");
    render(<InstrumentPanel />);
    expect(screen.getByText("Select a track")).toBeInTheDocument();
  });

  it("shows 'AUDIO TRACK' for audio tracks", async () => {
    useDawStore.setState({
      tracks: [makeTrack({ id: "a1", type: "audio" })],
      selectedTrackIds: ["a1"],
    });
    const { InstrumentPanel } = await import("@ui/panels");
    render(<InstrumentPanel />);
    expect(screen.getByText("AUDIO TRACK")).toBeInTheDocument();
  });

  it("shows SynthEditor for instrument tracks", async () => {
    const { useSynthStore } = await import("@state/synth/synth-store");
    useSynthStore.getState().initSynth("i1");
    useDawStore.setState({
      tracks: [makeTrack({ id: "i1", type: "instrument", color: "#D94A90" })],
      selectedTrackIds: ["i1"],
    });
    const { InstrumentPanel } = await import("@ui/panels");
    render(<InstrumentPanel />);
    expect(screen.getByTestId("synth-editor")).toBeInTheDocument();
  });

  it("shows DrumMachinePanel for drum tracks", async () => {
    useDawStore.setState({
      tracks: [makeTrack({ id: "d1", type: "drum", color: "#FF6B35" })],
      selectedTrackIds: ["d1"],
    });
    const { InstrumentPanel } = await import("@ui/panels");
    render(<InstrumentPanel />);
    expect(screen.getByTestId("drum-machine-panel")).toBeInTheDocument();
  });

  it("preserves drum params when switching tracks and back", async () => {
    const drumTrack = makeTrack({ id: "d3", type: "drum", color: "#FF6B35" });
    const audioTrack = makeTrack({ id: "a3", type: "audio" });
    useDawStore.setState({
      tracks: [drumTrack, audioTrack],
      selectedTrackIds: ["d3"],
    });
    const { InstrumentPanel } = await import("@ui/panels");
    const { rerender } = render(<InstrumentPanel />);

    // Find the "Vol" range input inside bass drum row
    const bdRow = screen.getByTestId("instrument-row-bd");
    const volSlider = bdRow.querySelector(
      'input[aria-label="Vol"]',
    ) as HTMLInputElement;
    expect(volSlider).not.toBeNull();
    expect(volSlider.value).toBe("0.9"); // DEFAULT_INSTRUMENT_PARAMS.bd.volume

    // Change volume via the range input
    fireEvent.change(volSlider, { target: { value: "0.42" } });
    expect(volSlider.value).toBe("0.42");

    // Switch to audio track (unmounts drum controller)
    act(() => {
      useDawStore.setState({ selectedTrackIds: ["a3"] });
    });
    rerender(<InstrumentPanel />);
    expect(screen.getByText("AUDIO TRACK")).toBeInTheDocument();

    // Switch back to drum track (remounts drum controller)
    act(() => {
      useDawStore.setState({ selectedTrackIds: ["d3"] });
    });
    rerender(<InstrumentPanel />);
    expect(screen.getByTestId("drum-machine-panel")).toBeInTheDocument();

    // Verify the param was preserved (not reset to default)
    const bdRowAfter = screen.getByTestId("instrument-row-bd");
    const volSliderAfter = bdRowAfter.querySelector(
      'input[aria-label="Vol"]',
    ) as HTMLInputElement;
    expect(volSliderAfter.value).toBe("0.42");
  });
});

/**
 * Bridge between the track Zustand store and live WebAudio instrument instances.
 * Subscribes to track additions/removals, creates/disposes SynthInstrument
 * and DrumKit instances, and forwards store parameter changes to audio engines.
 *
 * Follows the same pattern as EffectsBridge and RoutingBridge.
 */

import { useDawStore } from "@state/store";
import { useSynthStore } from "@state/synth/synth-store";
import type { SynthParameterMap } from "./synth/synth-types";
import { createSynthInstrument, type SynthInstrument } from "./synth/synth-instrument";
import { subscribeModRoutes } from "./synth/modulation-bridge";
import { createDrumKit } from "./drum-machine/drum-kit";
import type { DrumKit } from "./drum-machine/drum-types";
import { DRUM_INSTRUMENTS, type DrumInstrumentId } from "./drum-machine/drum-types";
import type { MixerEngine } from "./mixer/types";
import type { TrackModel } from "@state/track/types";

export type TrackAudioBridge = {
  getInstrument(trackId: string): SynthInstrument | undefined;
  getDrumKit(trackId: string): DrumKit | undefined;
  dispose(): void;
};

/**
 * Subscribe a SynthInstrument to param changes from useSynthStore.
 * Sends current params immediately, then diffs future changes.
 */
function subscribeSynthParams(
  trackId: string,
  instrument: SynthInstrument,
): () => void {
  // Send current params
  const current = useSynthStore.getState().getParams(trackId);
  for (const key of Object.keys(current) as (keyof SynthParameterMap)[]) {
    instrument.setParam(key, current[key]);
  }

  let prevRef = useSynthStore.getState().synths[trackId];

  return useSynthStore.subscribe((state) => {
    const synth = state.synths[trackId];
    if (!synth || synth === prevRef) return;

    const prevParams = prevRef?.params;
    prevRef = synth;

    if (!prevParams) return;

    for (const key of Object.keys(synth.params) as (keyof SynthParameterMap)[]) {
      if (synth.params[key] !== prevParams[key]) {
        instrument.setParam(key, synth.params[key]);
      }
    }
  });
}

/** Create silent placeholder AudioBuffers for each drum instrument. */
function createPlaceholderSamples(
  ctx: AudioContext,
): Map<DrumInstrumentId, AudioBuffer> {
  const samples = new Map<DrumInstrumentId, AudioBuffer>();
  for (const inst of DRUM_INSTRUMENTS) {
    samples.set(inst.id, ctx.createBuffer(1, 1, ctx.sampleRate));
  }
  return samples;
}

export function createTrackAudioBridge(
  ctx: AudioContext,
  mixer: MixerEngine,
): TrackAudioBridge {
  const instruments = new Map<string, SynthInstrument>();
  const drumKits = new Map<string, DrumKit>();
  const trackCleanups = new Map<string, () => void>();
  // Tracks with pending async instrument creation
  const alive = new Set<string>();
  let disposed = false;

  function addInstrumentTrack(trackId: string): void {
    alive.add(trackId);
    mixer.getOrCreateStrip(trackId);
    useSynthStore.getState().initSynth(trackId);

    createSynthInstrument(ctx).then((instrument) => {
      if (!alive.has(trackId) || disposed) {
        instrument.dispose();
        return;
      }

      instruments.set(trackId, instrument);
      instrument.connectToMixer(mixer, trackId);

      const unsubParams = subscribeSynthParams(trackId, instrument);
      const unsubMod = subscribeModRoutes(trackId, instrument);

      trackCleanups.set(trackId, () => {
        unsubParams();
        unsubMod();
        instrument.disconnectFromMixer(mixer, trackId);
        instrument.dispose();
        instruments.delete(trackId);
      });
    });
  }

  function addDrumTrack(trackId: string): void {
    alive.add(trackId);
    const samples = createPlaceholderSamples(ctx);
    const kit = createDrumKit(ctx, samples);
    drumKits.set(trackId, kit);
    kit.connectToMixer(mixer, trackId);

    trackCleanups.set(trackId, () => {
      kit.disconnectFromMixer(mixer, trackId);
      kit.dispose();
      drumKits.delete(trackId);
    });
  }

  function addAudioTrack(trackId: string): void {
    alive.add(trackId);
    mixer.getOrCreateStrip(trackId);
  }

  function handleTrackAdded(track: TrackModel): void {
    switch (track.type) {
      case "instrument":
        addInstrumentTrack(track.id);
        break;
      case "drum":
        addDrumTrack(track.id);
        break;
      case "audio":
        addAudioTrack(track.id);
        break;
    }
  }

  function handleTrackRemoved(trackId: string): void {
    alive.delete(trackId);
    trackCleanups.get(trackId)?.();
    trackCleanups.delete(trackId);
    mixer.removeStrip(trackId);
    useSynthStore.getState().removeSynth(trackId);
  }

  // Sync existing tracks on creation
  let prevTrackMap = new Map<string, TrackModel>();
  const initialTracks = useDawStore.getState().tracks;
  for (const track of initialTracks) {
    handleTrackAdded(track);
    prevTrackMap.set(track.id, track);
  }

  // Subscribe to future track changes
  const unsubStore = useDawStore.subscribe((state) => {
    const current = new Map(state.tracks.map((t) => [t.id, t]));

    // Added
    for (const [id, track] of current) {
      if (!prevTrackMap.has(id)) {
        handleTrackAdded(track);
      }
    }

    // Removed
    for (const id of prevTrackMap.keys()) {
      if (!current.has(id)) {
        handleTrackRemoved(id);
      }
    }

    prevTrackMap = current;
  });

  return {
    getInstrument(trackId: string): SynthInstrument | undefined {
      return instruments.get(trackId);
    },

    getDrumKit(trackId: string): DrumKit | undefined {
      return drumKits.get(trackId);
    },

    dispose(): void {
      disposed = true;
      unsubStore();

      for (const cleanup of trackCleanups.values()) {
        cleanup();
      }
      trackCleanups.clear();
      alive.clear();
    },
  };
}

